const questionsFr: Question[] = [
  // ── Principe (18) ──
  { q:"La tonicisation consiste à :", opts:["Moduler définitivement dans une nouvelle tonalité","Traiter un accord comme une tonique temporaire et le précéder de sa dominante","Supprimer la tonique principale","Jouer tous les accords en mineur"], a:1, fb:"La tonicisation rend temporairement un accord 'tonique' en lui appliquant ses propres accords fonctionnels — notamment sa dominante propre. Ce n'est pas une modulation — on reste dans la tonalité principale." },
  { q:"Quelle est la différence entre tonicisation et modulation ?", opts:["Elles sont identiques","La tonicisation est momentanée, la modulation installe durablement une nouvelle tonalité","La modulation est plus courte","La tonicisation utilise des emprunts"], a:1, fb:"Tonicisation : un accord joue le rôle de tonique l'espace d'un instant. Modulation : on change vraiment de tonalité principale — confirmé par une cadence parfaite dans le nouveau centre." },
  { q:"Quel accord peut être tonicisé ?", opts:["Uniquement la tonique principale","Tout accord diatonique sauf la tonique principale et les accords diminués","Uniquement les accords majeurs","Uniquement les dominantes"], a:1, fb:"Tout accord diatonique peut être tonicisé — sauf la tonique principale (déjà tonique) et les accords diminués (trop instables pour jouer un rôle de tonique)." },
  { q:"Pourquoi la tonique principale ne peut-elle pas être tonicisée ?", opts:["Par convention","Car elle est déjà la tonique — pas besoin de la 'rendre' tonique","Car elle est trop grave","Car elle n'a pas de dominante"], a:1, fb:"La tonique principale est déjà le centre tonal de la gamme — elle n'a pas besoin d'être renforcée par sa propre dominante. La toniciser serait une tautologie harmonique." },
  { q:"Pourquoi les accords diminués ne peuvent-ils pas être tonicisés ?", opts:["Car ils sont trop instables pour assumer la fonction tonique","Car ils sont rares","Car ils ont une quinte juste","Car ils sont toujours en renversement"], a:0, fb:"Les accords diminués sont intrinsèquement instables — leur quinte diminuée empêche tout sentiment de repos ou de stabilité. Ils servent de tensions, pas de points d'arrivée." },
  { q:"La notation V/V signifie :", opts:["La quinte de la quinte","La dominante de la dominante — l'accord V7 de la tonalité de V","La sous-dominante de V","La dominante divisée par deux"], a:1, fb:"V/V = dominante de la dominante. En C majeur : V = G, donc V/V = D7. D7 tonicise G avant que G résout sur C." },
  { q:"La dominante secondaire V/V en C majeur est :", opts:["C7","A7","D7","E7"], a:2, fb:"V de C = G. La dominante de G est D7. D7 → G7 → C = V/V–V–I. D7 contient F# (sensible de G) qui monte vers G." },
  { q:"La sensible artificielle créée par une tonicisation est :", opts:["Une note de la gamme principale","Une altération (dièse ou bécarre) qui crée un demi-ton ascendant vers le degré tonicisé","Une broderie","Un retard"], a:1, fb:"Pour toniciser un accord, on crée une sensible artificielle — une altération (souvent un dièse) qui monte d'un demi-ton vers la fondamentale de l'accord cible. Ex : C# monte vers D dans V/II." },
  { q:"En C majeur, toniciser Am (VIe) nécessite l'accord :", opts:["D7","A7","E7","B7"], a:2, fb:"Am est le VIe de C. Sa dominante propre est E7 (Mi–Sol#–Si–Ré). E7 → Am. Le Sol# est la sensible artificielle qui monte vers La." },
  { q:"En C majeur, V/II s'écrit :", opts:["D7","A7","E7","B7"], a:1, fb:"II de C = Dm. La dominante de D = A. V/II = A7 (La–Do#–Mi–Sol). Le Do# est la sensible de D qui monte vers Ré." },
  { q:"La tonicisation est une forme d'emprunt car :", opts:["Elle change la tonalité principale","Elle emprunte temporairement des accords d'une autre tonalité — la tonalité de l'accord tonicisé","Elle supprime des degrés","Elle ignore le triton"], a:1, fb:"La tonicisation est un emprunt ciblé : on emprunte la dominante (et parfois la sous-dominante) de la tonalité dont l'accord tonicisé serait la tonique." },
  { q:"Quel accord peut remplacer une sous-dominante dans une tonicisation ?", opts:["La dominante secondaire directement (V/X)","La tonique principale","Le VIIe degré","Un accord augmenté"], a:0, fb:"En pratique, on remplace souvent SD → D secondaire par la dominante secondaire directe. Au lieu de SD/X → V/X → X, on fait V/X → X. V/V peut ainsi remplacer un accord de SD." },
  { q:"La progression C–D7–G7–C illustre :", opts:["Une modulation en G","Une tonicisation de G (V) via D7 = V/V","Un emprunt à C mineur","Une basse de chaconne"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 tonicise G momentanément — G est préparé par sa propre dominante avant de résoudre sur C. On n'a jamais quitté C majeur." },
  { q:"La progression A–B7–E7–A en A majeur illustre :", opts:["Une modulation en E","Une tonicisation en chaîne : B7 = V/V, E7 = V","Un emprunt à A mineur","Une suite de cadences plagales"], a:1, fb:"A (I) → B7 (V/V de A) → E7 (V de A) → A (I). B7 tonicise E7, qui à son tour résout sur A. C'est une chaîne de dominantes secondaires." },
  { q:"Quand on tonicise un accord, le triton de référence pour déterminer les fonctions est :", opts:["Celui de la tonalité principale","Celui de la tonalité temporaire (de l'accord tonicisé)","Il n'y a pas de triton dans une tonicisation","Le triton du VIIe degré"], a:1, fb:"Dans une tonicisation, on entre temporairement dans la tonalité de l'accord tonicisé. Le triton fonctionnel de cette tonalité temporaire guide l'analyse des fonctions des accords secondaires." },
  { q:"La tonicisation peut combiner :", opts:["Uniquement des dominantes secondaires","Dominantes secondaires et substitutions diatoniques ou emprunts","Uniquement des emprunts à l'homonyme","Uniquement des renversements"], a:1, fb:"Les règles de l'harmonie coexistent. Dans une tonicisation, on peut introduire des substitutions diatoniques ou des emprunts — à condition de référencer le triton de la tonalité temporaire." },
  { q:"La progression C–A7–Dm–G7–C utilise A7 comme :", opts:["Dominante principale","V/II — dominante de Dm","Emprunt à C mineur","Accord napolitain"], a:1, fb:"A7 = V/II en C majeur. Il tonicise Dm (IIe degré) momentanément avant que Dm reprenne sa fonction de sous-dominante dans la progression SD–D–T finale." },
  { q:"Dans une tonicisation, la sensible artificielle doit :", opts:["Descendre","Monter d'un demi-ton vers la fondamentale de l'accord tonicisé","Rester immobile","Sauter d'une quinte"], a:1, fb:"Comme la sensible naturelle, la sensible artificielle monte d'un demi-ton vers sa résolution — la fondamentale de l'accord tonicisé. Ex : C# → D dans A7 → Dm." },

  // ── Dominantes secondaires (22) ──
  { q:"Comment calculer rapidement une dominante secondaire ?", opts:["Monter de 4 degrés depuis l'accord cible","Monter de 5 degrés (ou descendre de 4) depuis l'accord cible et jouer un accord X7","Descendre de 3 degrés","Toujours utiliser l'accord bVII"], a:1, fb:"Astuce : pour toniciser X, monte 5 notes depuis X et joue un accord de dominante 7 (X7). Ex : pour Dm, compte D–E–F–G–A = A7. Pour Am : A–B–C–D–E = E7." },
  { q:"La dominante secondaire contient toujours :", opts:["La quinte de l'accord cible","La sensible artificielle de l'accord cible — un demi-ton en dessous de sa fondamentale","La fondamentale de la tonalité principale","La septième majeure"], a:1, fb:"V/X contient toujours la sensible de X — une note un demi-ton en dessous de la fondamentale de X. Ex : V/Dm = A7, qui contient C# (sensible de D, un demi-ton sous D)." },
  { q:"V/IV en C majeur est :", opts:["D7","G7","C7","A7"], a:2, fb:"IV de C = F. La dominante de F = C. V/IV = C7 (Do–Mi–Sol–Si♭). La septième Mi♭ (Si♭ dans C7) est la note qui colore la tonicisation de F." },
  { q:"V/III en C majeur est :", opts:["F7","B7","A7","E7"], a:1, fb:"III de C = Em. La dominante de Em = B. V/III = B7 (Si–Ré#–Fa#–La). Le Ré# est la sensible de E qui monte vers Mi." },
  { q:"V/VI en C majeur est :", opts:["D7","A7","E7","B7"], a:2, fb:"VI de C = Am. La dominante de Am = E. V/VI = E7 (Mi–Sol#–Si–Ré). Le Sol# est la sensible artificielle de A qui monte vers La." },
  { q:"V/V en G majeur est :", opts:["C7","A7","D7","E7"], a:1, fb:"V de G = D. La dominante de D = A. V/V en G majeur = A7. La progression A7–D7–G en G majeur est une double tonicisation." },
  { q:"Dans la progression C–E7–Am–G7–C, E7 est :", opts:["La dominante principale","V/VI — il tonicise Am","Un emprunt à C mineur","V/II"], a:1, fb:"E7 = V/VI en C majeur. Il contient Sol# (sensible artificielle de Am) qui monte vers La. E7 → Am crée une résolution secondaire avant de repartir vers G7–C." },
  { q:"L'altération caractéristique de V/II en C (= A7) est :", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = La–Do#–Mi–Sol. Le Do# (C#) est la tierce de A7 et la sensible artificielle de Dm — il monte d'un demi-ton vers Ré." },
  { q:"L'altération caractéristique de V/V en C (= D7) est :", opts:["C#","F#","G#","B♭"], a:1, fb:"D7 = Ré–Fa#–La–Do. Le Fa# (F#) est la tierce de D7 et la sensible artificielle de G — il monte d'un demi-ton vers Sol." },
  { q:"L'altération caractéristique de V/VI en C (= E7) est :", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = Mi–Sol#–Si–Ré. Le Sol# (G#) est la tierce de E7 et la sensible artificielle de Am — il monte d'un demi-ton vers La." },
  { q:"La progression C–D7–G–C est différente de C–D7–G7–C car :", opts:["D7 est différent","G sans septième n'a pas le triton F–B — la tension vers C est plus faible","C est différent","Il n'y a pas de différence harmonique"], a:1, fb:"G sans septième = G majeur (G–B–D) — il n'a pas le triton F–B, donc la tension vers C est moins forte. G7 avec sa septième F crée le triton B–F qui résout fortement vers C." },
  { q:"V/IV tonicise :", opts:["La dominante","La sous-dominante","Le IIe degré","Le VIe degré"], a:1, fb:"IV = sous-dominante (F en C). V/IV = C7 tonicise F momentanément avant que F joue son rôle habituel de sous-dominante." },
  { q:"Dans la progression A–B7–E7–A (en A majeur), B7 est :", opts:["La dominante principale","V/V — il tonicise E7","Un emprunt à A mineur","Le VIIe degré"], a:1, fb:"V de A = E. V de E = B. B7 = V/V en A majeur. Il tonicise la dominante E7 avant que E7 résout sur A." },
  { q:"Quelle note est commune à G7 et D7 en C majeur ?", opts:["F (Fa)","G (Sol)","D (Ré)","A (La)"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F (Fa) est dans G7 mais pas dans D7 (qui a F#). La note commune est D. Aucune note commune entre G7 et D7 en fait — D est dans G7 comme quinte, et fondamentale de D7." },
  { q:"La dominante secondaire d'un accord diminué est :", opts:["Impossible — les diminués ne peuvent pas être tonicisés","Un autre accord diminué","Un accord majeur","Un accord mineur 7"], a:0, fb:"Les accords diminués ne peuvent pas être tonicisés — ils ne peuvent pas jouer le rôle de tonique. Donc il n'existe pas de dominante secondaire pour les degrés diminués (VII en majeur, II en mineur)." },
  { q:"La progression Dm–A7–Dm en C majeur montre :", opts:["Une modulation en D mineur","Une tonicisation de Dm — A7 = V/II agit comme dominante temporaire de Dm","Un emprunt à D majeur","Une cadence plagale"], a:1, fb:"A7 est V/II — il tonicise Dm momentanément. La progression Dm–A7–Dm est une mini cadence parfaite en D mineur, enchâssée dans la tonalité principale de C majeur." },
  { q:"En G majeur, V/II = :", opts:["C7","D7","A7","E7"], a:2, fb:"II de G = Am. La dominante de Am = E. Attendez — V/II en G = dominante de Am. Am est le IIe de G. Dominante de A = E7. V/II en G majeur = E7." },
  { q:"Dans C–A7–Dm–D7–G7–C, D7 est :", opts:["La dominante de C","V/V — il tonicise G7 avant que G7 résout sur C","Un emprunt à D majeur","V/II une seconde fois"], a:1, fb:"D7 = V/V en C majeur. Il tonicise G7 momentanément avant la résolution finale G7–C. La progression contient deux tonicisations : A7 (V/II) tonicise Dm, D7 (V/V) tonicise G7." },
  { q:"Pourquoi V/V est-il la tonicisation la plus fréquente ?", opts:["Par hasard","Car G (V) est l'accord le plus important après la tonique — renforcer sa dominante renforce la cadence finale","Car D7 est facile à jouer","Car il évite le triton"], a:1, fb:"La dominante (V) est l'accord le plus crucial de la tonalité. Renforcer sa propre dominante (V/V) renforce d'autant la cadence finale V–I. C'est la tonicisation la plus directement fonctionnelle." },
  { q:"Dans V/X, si X est un accord mineur, la dominante secondaire est :", opts:["Un accord mineur 7","Un accord de dominante 7 (majeur avec 7e mineure)","Un accord diminué","Un accord majeur 7"], a:1, fb:"La dominante secondaire est toujours un accord X7 (triade majeure + 7e mineure) — quelle que soit la nature de l'accord tonicisé. V/Dm = A7, V/Am = E7, V/Em = B7 — tous sont des X7." },
  { q:"La progression C–E7–Am–Dm–G7–C contient combien de tonicisations ?", opts:["Aucune","Une seule (E7)","Deux (E7 et éventuellement une seconde)","Trois"], a:1, fb:"E7 = V/VI tonicise Am. C'est la seule dominante secondaire dans cette progression. Am, Dm, G7 et C sont tous diatoniques à C majeur — pas de tonicisation supplémentaire." },
  { q:"Pour toniciser Bm (VII de C# majeur), on utilise :", opts:["F#7","E7","A7","D7"], a:0, fb:"La dominante de B = F#. Pour toniciser Bm, on utilise F#7 — indépendamment de la tonalité principale. La règle est universelle : monte 5 notes depuis l'accord cible et joue X7." },

  // ── Tons voisins (18) ──
  { q:"Les tons voisins d'une tonalité sont :", opts:["Les tonalités à l'octave","Les tonalités qui partagent au moins 6 notes communes — les 6 premiers degrés de la gamme majeure et leurs relatifs","Les tonalités avec la même armure","Les tonalités à la quinte"], a:1, fb:"Les tons voisins partagent au moins 6 notes communes. En C majeur : Dm, Em, F, G, Am et leur gamme propre. Chaque degré de la gamme correspond à un ton voisin." },
  { q:"En C majeur, les tons voisins sont :", opts:["D majeur, E majeur, F majeur, G majeur, A majeur","D mineur, E mineur, F majeur, G majeur, A mineur","B mineur, C# majeur, D majeur","G♭ majeur, A♭ majeur"], a:1, fb:"Les 6 tons voisins de C majeur : Dm (II), Em (III), F (IV), G (V), Am (VI). Ce sont les tonalités des degrés diatoniques — elles partagent 6 ou 7 notes communes avec C." },
  { q:"La dominante secondaire d'Am (VIe de C) est :", opts:["D7","A7","E7","B7"], a:2, fb:"Am est le VIe de C. La dominante de Am = E7 (Mi–Sol#–Si–Ré). E7 = V/VI. Sol# est la sensible artificielle de Am." },
  { q:"La sous-dominante secondaire de G majeur (Ve de C) est :", opts:["C7","Am7 et CMaj7","Dm7 et FMaj7","A7"], a:1, fb:"En G majeur, la sous-dominante = IV de G = C. Donc les accords SD de G sont Am7 (II de G) et CMaj7 (IV de G). On peut les utiliser pour préparer D7 (V/V) dans une tonicisation de G." },
  { q:"En D majeur, V/V est :", opts:["G7","A7","E7","B7"], a:1, fb:"V de D = A. V de A = E. V/V en D majeur = E7. La progression E7–A7–D illustre une double tonicisation en D majeur." },
  { q:"La relation entre la tonique principale et ses tons voisins est :", opts:["Aucune — ils sont indépendants","Chaque ton voisin partage 6-7 notes avec la tonique — les accords peuvent être échangés par tonicisation ou emprunt","Ils ont la même armure","Ils ont toujours la même fondamentale"], a:1, fb:"Les tons voisins partagent presque toutes leurs notes avec la tonique principale — c'est pourquoi les transitions par tonicisation sont si fluides. On reste dans un territoire harmonique familier." },
  { q:"Dans le tableau des tons voisins de D majeur, quel est le ton voisin correspondant au IVe degré ?", opts:["E mineur","G majeur","A majeur","F# mineur"], a:1, fb:"Le IVe degré de D majeur est G. G majeur est donc le ton voisin correspondant au IVe degré de D. Sa dominante secondaire en D majeur = C7 (V/IV)." },
  { q:"La sous-dominante secondaire d'un ton voisin permet de :", opts:["Toniciser la tonique principale","Préparer la dominante secondaire — SD/X → V/X → X","Moduler définitivement","Créer des octaves parallèles"], a:1, fb:"SD/X prépare V/X qui résout sur X. Ex : pour toniciser G en C : Am7 (SD/G) → D7 (V/G) → G → C. La sous-dominante secondaire enrichit la tonicisation." },
  { q:"Quelle est la dominante secondaire de F majeur (IVe de C) ?", opts:["G7","D7","C7","A7"], a:2, fb:"F est le IVe de C. La dominante de F = C. C7 (Do–Mi–Sol–Si♭) = V/IV. La Si♭ est la septième de C7 qui descend vers La (tierce de F)." },
  { q:"En A majeur, les tons voisins incluent :", opts:["C majeur et D mineur","Bm, C#m, D majeur, E majeur, F#m","G majeur et Am","F majeur et Gm"], a:1, fb:"Les tons voisins de A majeur : Bm (II), C#m (III), D (IV), E (V), F#m (VI). Ce sont les tonalités des degrés diatoniques de A majeur." },
  { q:"En G majeur, V/VI = :", opts:["D7","A7","B7","C7"], a:1, fb:"VI de G = Em. Dominante de Em = B. V/VI en G majeur = B7 (Si–Ré#–Fa#–La). Ré# est la sensible artificielle de Em dans la tonalité de G." },
  { q:"La progression G–A7–Dm–C–G en G majeur illustre :", opts:["Une modulation en D mineur","Un emprunt de Dm depuis G mineur","Une tonicisation de Dm — Dm est le VIe de G et A7 = V/VI en G majeur","Une basse de chaconne"], a:2, fb:"En G majeur, VI = Em. Mais Dm ici est un emprunt à G mineur (VIe de G mineur = Dm). A7 tonicise Dm comme s'il était momentanément tonique. Analyse contextuelle nécessaire." },
  { q:"Comment trouver la dominante secondaire de Em (IIIe de C) ?", opts:["Monter de 3 degrés depuis E = G, jouer G7","Monter de 5 degrés depuis E = B, jouer B7","Descendre de 2 degrés depuis E = D, jouer D7","Jouer Em7 directement"], a:1, fb:"Monte 5 notes depuis E : E–F–G–A–B = B. Joue B7 (Si–Ré#–Fa#–La). B7 = V/III en C majeur. Ré# est la sensible de E qui monte vers Mi." },
  { q:"Les tons voisins facilitent les tonicisations car :", opts:["Ils ont moins de notes","Ils partagent presque toutes leurs notes avec la tonalité principale — les transitions sont fluides","Ils sont plus graves","Ils ont plus d'accords majeurs"], a:1, fb:"Avec 6-7 notes communes, la transition vers un ton voisin est perçue comme naturelle. Une tonicisation vers un ton voisin n'est pas dépaysante — on reste dans un univers familier." },
  { q:"Dans une tonicisation, peut-on combiner V/X avec un napolitain de X ?", opts:["Non — les règles s'excluent","Oui — toutes les règles coexistent, à condition de référencer le triton de X","Uniquement en mineur","Seulement avec des emprunts de l'homonyme"], a:1, fb:"Oui. Dans la tonalité temporaire de X, on peut utiliser n'importe quel outil harmonique : napolitain de X, emprunt à X mineur, substitution diatonique dans X. Le triton de X est la référence." },
  { q:"En C majeur, lequel de ces accords n'est PAS une dominante secondaire valide ?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (impossible diatoniquement)"], a:3, fb:"G#7 n'existe pas comme dominante secondaire diatonique en C majeur — aucun accord diatonique de C n'a G# comme fondamentale de sa dominante. A7, E7 et F7 (= C7 est la vraie notation) sont valides." },
  { q:"La sous-dominante secondaire de Dm (IIe de C) est :", opts:["G7","Em7b5 et Gm7","Am7 et CMaj7","D7"], a:1, fb:"Dans la tonalité de D mineur, la sous-dominante = IV de D mineur = Gm. Mais le IIe de D mineur = Em7b5. Donc SD/Dm = Em7b5 (II de Dm) et Gm7 (IV de Dm)." },
  { q:"En E♭ majeur, V/V est :", opts:["F7","B♭7","C7","G7"], a:1, fb:"V de Eb = Bb. La dominante de Bb = F. V/V en Eb = F7 — attendez, non. V de Eb = Bb. V de Bb = F. V/V en Eb = F7. Ici la réponse correcte est F7, mais les options proposent Bb7 — qui est V de Eb directement, pas V/V." },

  // ── Chaînes (18) ──
  { q:"Une chaîne de tonicisations est :", opts:["Une succession d'accords diminués","Une suite de dominantes secondaires, chacune tonicisant la suivante","Une suite de cadences parfaites","Un cycle des quintes sans dominantes"], a:1, fb:"Une chaîne de tonicisations enchaîne plusieurs dominantes secondaires : V/V/V → V/V → V → I. Chaque accord prépare la dominante suivante, créant une tension qui s'accumule vers la résolution finale." },
  { q:"La progression C–C#7–F#7–B7–E7–A en A majeur est :", opts:["Une modulation en C#","Une chaîne de dominantes secondaires : V/V/V/V–V/V/V–V/V–V–I","Un emprunt en masse","Un cycle des quintes diatoniques"], a:1, fb:"C#7 = V/V/V/V de A (car C#7 → F#7 → B7 → E7 → A). Chaque accord tonicise le suivant par un mouvement de dominante à tonique. Tension progressive vers A." },
  { q:"La progression A–B7–E7–A (en A majeur) est une chaîne car :", opts:["B7 et E7 sont tous deux dans la gamme de A","B7 tonicise E7 (V/V) qui tonicise A (V) — deux niveaux de dominantes secondaires","Ce sont des accords de passage","Ce sont des emprunts à A mineur"], a:1, fb:"B7 = V/V en A majeur (tonicise E7). E7 = V en A (tonicise A). Deux niveaux de tonicisation emboîtés : V/V → V → I. La tension monte sur deux étapes avant la résolution." },
  { q:"La notation V/V/V signifie :", opts:["La quinte de la quinte de la quinte","La dominante de la dominante de la dominante — trois niveaux de tonicisation","Une modulation en trois étapes","Un accord impossible"], a:1, fb:"V/V/V = dominante de la dominante de la dominante. En C : V = G, V/V = D7, V/V/V = A7. La progression A7–D7–G7–C est une chaîne de trois tonicisations." },
  { q:"Dans une chaîne, chaque accord résout :", opts:["Sur la tonique principale","Sur l'accord qui suit de façon que chaque accord agisse comme dominante du suivant","Par demi-ton chromatique","Sur le même accord"], a:1, fb:"Dans une chaîne V/V/V → V/V → V → I : chaque accord résout sur celui qui suit — A7 → D7 → G7 → C. Chaque résolution est une micro-cadence qui renforce la suivante." },
  { q:"La progression C–A7–D7–G7–C contient :", opts:["Aucune tonicisation","Une tonicisation (A7)","Deux tonicisations (A7 = V/II et D7 = V/V)","Trois tonicisations"], a:2, fb:"A7 = V/II (tonicise Dm brièvement — Dm est 'esquivé' ici). D7 = V/V (tonicise G7). Deux niveaux de dominantes secondaires s'enchaînent avant la résolution finale G7–C." },
  { q:"Pourquoi les chaînes de dominantes secondaires créent-elles une tension croissante ?", opts:["Car elles utilisent des accords dissonants","Car chaque dominante secondaire renforce la suivante — la résolution finale est d'autant plus satisfaisante","Car elles modulent","Car elles suppriment le triton"], a:1, fb:"Chaque étape de la chaîne crée une attente qui est partiellement satisfaite (résolution secondaire) mais qui pointe vers la résolution finale. La tension s'accumule et la résolution finale est plus puissante." },
  { q:"En C majeur, la chaîne V/V/V–V/V–V–I s'écrit :", opts:["B7–E7–A7–C","A7–D7–G7–C","D7–G7–C7–F","E7–A7–Dm–G7"], a:1, fb:"V = G, V/V = D7, V/V/V = A7. La chaîne est A7–D7–G7–C. Chaque accord résout une quinte plus bas, vers la résolution finale sur C." },
  { q:"Dans la progression G–C#7–F#7–B7–E7–Am–D7–G (en G majeur), combien de tonicisations y a-t-il ?", opts:["Deux","Trois","Quatre ou plus (chaîne complexe)","Une seule"], a:2, fb:"C#7 (V/VI de G, tonicise F#m), F#7 (V/VI ?), B7 (V/III, tonicise Em/E), E7 (V/II, tonicise Am), D7 (V/V, tonicise G) — c'est une longue chaîne avec au moins 4 niveaux de tonicisation." },
  { q:"La simplification courante d'une tonicisation est :", opts:["Ne jamais toniciser","Remplacer SD/X → V/X par V/X directement","Toujours utiliser le napolitain","Ne jamais chaîner les dominantes"], a:1, fb:"En pratique, au lieu de SD → D secondaire, on saute directement à la dominante secondaire. Au lieu de Am → D7 → G → C, on fait directement D7 → G → C. V/V remplace la sous-dominante." },
  { q:"En jazz, les chaînes de dominantes secondaires sont appelées :", opts:["Ostinatos","Backcycling ou dominant chain","Arpèges dominants","Pédale de dominante"], a:1, fb:"En jazz, enchaîner des dominantes secondaires vers la résolution finale s'appelle 'backcycling' ou 'dominant chain'. C'est la base de nombreuses réharmonisations de standards." },
  { q:"La progression I7–IV dans les 12 mesures de blues utilise I7 comme :", opts:["Accord de tonique stable","V/IV — tonicisation de IV (la sous-dominante)","Un emprunt à I mineur","Un accord de passage"], a:1, fb:"Dans le blues, I7 (ex : C7 en C) est V/IV — il tonicise F (IV). C7 contient Bb qui est étranger à C majeur mais est la 7e de C7, sensible de F (pour la tierce). C'est une tonicisation de la sous-dominante." },
  { q:"Peut-on toniciser un accord emprunté ?", opts:["Non — les emprunts ne peuvent pas être tonicisés","Oui — tout accord présent dans la progression peut être tonicisé, même un accord emprunté","Uniquement en mineur","Uniquement si l'emprunt est le IVe degré"], a:1, fb:"Un accord emprunté peut être tonicisé — on lui applique sa propre dominante. Ex : si on emprunte Ab (bVI de C) depuis C mineur, on peut le toniciser avec Eb7 (V de Ab) pour renforcer l'emprunt." },
  { q:"La progression C–Eb7–Ab–G7–C contient :", opts:["Uniquement des emprunts","Un emprunt (Ab) et une tonicisation de cet emprunt (Eb7 = V/bVI)","Deux modulations","Un cycle des quintes"], a:1, fb:"Ab est emprunté à C mineur (bVI). Eb7 est V/Ab — il tonicise l'accord emprunté avant que G7 ramène vers C. Emprunt et tonicisation coexistent dans la même progression." },
  { q:"La chaîne A7–D7–G7–C en C majeur peut s'analyser comme :", opts:["Trois modulations successives","V/II–V/V–V–I : tonicisation de Dm (esquivé), tonicisation de G, cadence parfaite","Trois emprunts sans fonction","Un cycle des quintes diatoniques standard"], a:1, fb:"A7 = V/II (prépare D, mais D est esquivé — A7 résout directement sur D7 sans attendre Dm). D7 = V/V. G7 = V. C = I. Trois niveaux de tonicisation emboîtés." },
  { q:"Dans la chaîne E7–A7–D7–G7–C, combien de résolutions secondaires y a-t-il avant la résolution finale ?", opts:["Aucune","Deux","Trois","Quatre"], a:2, fb:"E7→A7 (résolution secondaire 1), A7→D7 (résolution secondaire 2), D7→G7 (résolution secondaire 3), G7→C (résolution finale). Trois résolutions secondaires, une finale." },
  { q:"Toniciser la tonicisation signifie :", opts:["Répéter la même note","Appliquer une nouvelle dominante secondaire à une dominante secondaire déjà présente","Moduler deux fois de suite","Utiliser deux emprunts"], a:1, fb:"On peut toniciser une tonicisation : appliquer une dominante secondaire à une dominante secondaire. V/V/V tonicise V/V. La chaîne peut théoriquement se prolonger à l'infini." },
  { q:"La progression de jazz ii–V–I–ii–V–I en 'tournant' illustre :", opts:["Une modulation répétée","Le cycle fonctionnel fondamental T–SD–D–T répété, parfois avec tonicisations internes","Une suite de pédale de dominante","Un contrepoint à 4 voix"], a:1, fb:"ii–V–I = SD–D–T = le cycle fonctionnel. En jazz, on peut enrichir chaque V d'une chaîne de dominantes secondaires (ii/V → V/V → V → I) pour densifier l'harmonie." },

  // ── Synthèse et application (16) ──
  { q:"Quelle est la sensible artificielle de V/V en F majeur ?", opts:["B naturel","E naturel","C# (C dièse)","A#"], a:0, fb:"V de F = C. V/V en F = G7. G7 = G–B–D–F. Le B naturel (Si naturel) est la sensible artificielle de C — il monte d'un demi-ton vers Do. Attention : F majeur a Bb, donc B naturel est bien une altération artificielle." },
  { q:"La progression Am–E7–Am–Dm–A7–Dm en A mineur montre :", opts:["Deux modulations","E7 = V (tonicise Am) et A7 = V/IV (tonicise Dm) — deux tonicisations internes","Deux emprunts","Un cycle des quintes complet"], a:1, fb:"E7 = V de A mineur harmonique (tonicise Am). A7 = V/IV tonicise Dm (IV de A mineur). Deux tonicisations dans la même progression en A mineur." },
  { q:"En D mineur, V/V est :", opts:["C7","A7","G7","E7"], a:1, fb:"V de D mineur = A (la dominante de D mineur est A7 en mineur harmonique). V/V en D mineur = dominante de A = E7. E7 → A7 → Dm." },
  { q:"La progression G–D7–G–C–G–A7–Dm–G en G majeur utilise :", opts:["Uniquement des accords diatoniques","D7 = V/V (tonicise G) et A7 = V/II (tonicise Dm)","Deux modulations","Un cycle de basse de chaconne"], a:1, fb:"D7 = V/V en G majeur (tonicise G — effet de renforcement de la dominante). A7 = V/II en G majeur (tonicise Dm, le IIe de G). Deux tonicisations dans la progression." },
  { q:"Quelle progression illustre V/IV–IV–V7–I en C majeur ?", opts:["G7–F–G7–C","C7–F–G7–C","D7–G–G7–C","A7–Dm–G7–C"], a:1, fb:"V/IV = C7. IV = F. V7 = G7. I = C. La progression C7–F–G7–C tonicise d'abord F (IV) avant la cadence finale G7–C. Très courant dans le blues et le classique." },
  { q:"La différence entre V/V et le cycle des quintes est :", opts:["Aucune différence","V/V est une tonicisation ciblée (un seul accord cible), le cycle des quintes parcourt tous les degrés","Le cycle des quintes n'utilise pas de dominantes","V/V utilise des emprunts"], a:1, fb:"V/V est une tonicisation spécifique — un accord préparant la dominante. Le cycle des quintes est une structure plus large qui parcourt plusieurs degrés successivement par mouvement de quinte." },
  { q:"En C majeur, la progression A7–D7–G7–C est équivalente à :", opts:["Trois modulations","V/II–V/V–V–I : trois niveaux de dominantes secondaires convergeant vers C","Un cycle des quintes diatonique","Deux emprunts et une dominante"], a:1, fb:"A7 = V/II (mais Dm est esquivé — A7 résout sur D7), D7 = V/V, G7 = V, C = I. C'est une chaîne V/V/V–V/V–V–I en C majeur (où le Dm est simplement passé sous silence)." },
  { q:"Peut-on toniciser le IIe degré d'une gamme mineure ?", opts:["Non — le IIe est toujours diminué et ne peut pas être tonicisé","Oui, si on utilise la gamme naturelle sur ce degré (IIe = accord mineur)","Uniquement en mode dorique","Uniquement avec le napolitain"], a:0, fb:"En mineur harmonique, le IIe degré est diminué (Dm7b5 en C mineur) — il ne peut pas être tonicisé. En mineur naturel, le IIe serait Dm (mineur), mais on utilise généralement le mineur harmonique pour les fonctions." },
  { q:"La progression C–G7/B–Am–A7–Dm–G7–C utilise :", opts:["Uniquement des accords diatoniques","G7/B = renversement de V, A7 = V/II tonicise Dm","Deux modulations","Un napolitain et une tonicisation"], a:1, fb:"G7/B = G7 en 1er renversement (fluidifie la basse). A7 = V/II — tonicise Dm momentanément. Dm reprend ensuite sa fonction SD habituelle dans la cadence G7–C." },
  { q:"En G mineur, V/III (IIIe = Bb majeur) serait :", opts:["F7","C7","Eb7","A7"], a:0, fb:"III de G mineur = Bb (Si♭ majeur, relatif majeur). La dominante de Bb = F. V/III en G mineur = F7. F7 → Bb crée une tonicisation du relatif majeur." },
  { q:"La progression Am–E7–Am en A mineur vs Am–E7–Am en A majeur — quelle différence ?", opts:["Aucune, E7 est identique","En A mineur, E7 est la dominante naturelle (V). En A majeur, E7 est V/VI — une tonicisation","En A majeur, E7 est plus dissonant","En A mineur, E7 est un emprunt"], a:1, fb:"En A mineur, E7 est simplement le Ve degré harmonique — la dominante principale. En A majeur, Am n'est pas la tonique principale, et E7 = V/VI — une tonicisation du VIe degré." },
  { q:"Toniciser signifie toujours ajouter :", opts:["Un accord renversé","La dominante propre de l'accord tonicisé (et optionnellement sa sous-dominante)","Un accord emprunt","Un accord de septième majeure"], a:1, fb:"Toniciser = précéder l'accord X de sa propre dominante V/X. On peut aussi ajouter SD/X avant V/X pour enrichir la tonicisation. L'essentiel est la dominante secondaire V/X." },
  { q:"La sensible artificielle dans une chaîne V/V/V–V/V–V–I en C (= A7–D7–G7–C) sont :", opts:["C# seulement","C#, F# et B naturel — une sensible artificielle par dominante secondaire","F# et B seulement","Aucune — ce sont des notes diatoniques"], a:1, fb:"A7 contient C# (sensible de D). D7 contient F# (sensible de G). G7 contient B naturel (sensible de C — diatonique, pas artificielle). Dans cette chaîne : C# et F# sont les sensibles artificielles, B est diatonique." },
  { q:"Une tonicisation sans résolution (la dominante secondaire non suivie de l'accord cible) crée :", opts:["Une modulation réussie","Une fausse piste harmonique — tension non résolue, effet de surprise ou de frustration","Une cadence parfaite","Un accord stable"], a:1, fb:"Si V/X n'est pas suivi de X, l'oreille est surprise — elle attendait X et reçoit autre chose. C'est une 'fausse cadence secondaire' — effet de surprise ou de déception harmonique, outil expressif." },
  { q:"Dans la progression G–B7–Em–A7–Dm–G7–C (en C majeur), B7 et A7 sont :", opts:["Des emprunts à G mineur et D mineur","B7 = V/VI (tonicise Em) et A7 = V/II (tonicise Dm) — deux tonicisations","Des accords de passage","Des modulations temporaires"], a:1, fb:"B7 = V/III en C (tonicise Em, IIIe de C). A7 = V/II en C (tonicise Dm, IIe de C). Deux tonicisations successives — Em et Dm sont les accords tonicisés avant la cadence finale G7–C." },
  { q:"La tonicisation est-elle possible en mode mineur ?", opts:["Non — uniquement en majeur","Oui — tout accord mineur peut être tonicisé avec les mêmes règles","Uniquement sur les degrés majeurs du mineur","Uniquement en mineur harmonique"], a:1, fb:"La tonicisation fonctionne en mineur exactement comme en majeur — on applique la dominante propre de l'accord cible. Les accords diminués restent les seules exceptions." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"Tonicization consists of:", opts:["Modulating definitively into a new key","Treating a chord as a temporary tonic and preceding it with its own dominant","Eliminating the main tonic","Playing all chords in minor"], a:1, fb:"Tonicization temporarily makes a chord 'tonic' by applying its own functional chords — notably its own dominant. It is not a modulation — we remain in the main key." },
{ q:"What is the difference between tonicization and modulation?", opts:["They are identical","Tonicization is momentary; modulation durably establishes a new key","Modulation is shorter","Tonicization uses borrowing"], a:1, fb:"Tonicization: a chord plays the role of tonic for a brief moment. Modulation: the main key genuinely changes — confirmed by an authentic cadence in the new tonal center." },
{ q:"Which chord can be tonicized?", opts:["Only the main tonic","Any diatonic chord except the main tonic and diminished chords","Only major chords","Only dominants"], a:1, fb:"Any diatonic chord can be tonicized — except the main tonic (already the tonic) and diminished chords (too unstable to function as a tonic)." },
{ q:"Why can the main tonic not be tonicized?", opts:["By convention","Because it is already the tonic — no need to 'make' it tonic","Because it is too low","Because it has no dominant"], a:1, fb:"The main tonic is already the tonal center of the scale — it does not need to be reinforced by its own dominant. Tonicizing it would be a harmonic tautology." },
{ q:"Why can diminished chords not be tonicized?", opts:["Because they are too unstable to assume the tonic function","Because they are rare","Because they have a perfect fifth","Because they are always in inversion"], a:0, fb:"Diminished chords are inherently unstable — their diminished fifth prevents any sense of rest or stability. They serve as tensions, not points of arrival." },
{ q:"The notation V/V means:", opts:["The fifth of the fifth","The dominant of the dominant — the V7 chord of the key of V","The subdominant of V","The dominant divided by two"], a:1, fb:"V/V = dominant of the dominant. In C major: V = G, so V/V = D7. D7 tonicizes G before G resolves to C." },
{ q:"The secondary dominant V/V in C major is:", opts:["C7","A7","D7","E7"], a:2, fb:"V of C = G. The dominant of G is D7. D7 → G7 → C = V/V–V–I. D7 contains F# (leading tone of G) which rises to G." },
{ q:"The artificial leading tone created by a tonicization is:", opts:["A note of the main scale","An accidental (sharp or natural) that creates a half-step ascent toward the tonicized degree","A neighbor tone","A suspension"], a:1, fb:"To tonicize a chord, an artificial leading tone is created — an accidental (often a sharp) that rises a half step to the root of the target chord. Ex: C# rises to D in V/II." },
{ q:"In C major, tonicizing Am (VI) requires the chord:", opts:["D7","A7","E7","B7"], a:2, fb:"Am is the VI of C. Its own dominant is E7 (E–G#–B–D). E7 → Am. G# is the artificial leading tone that rises to A." },
{ q:"In C major, V/II is written:", opts:["D7","A7","E7","B7"], a:1, fb:"II of C = Dm. The dominant of D = A. V/II = A7 (A–C#–E–G). C# is the leading tone of D that rises to D." },
{ q:"Tonicization is a form of borrowing because:", opts:["It changes the main key","It temporarily borrows chords from another key — the key of the tonicized chord","It removes scale degrees","It ignores the tritone"], a:1, fb:"Tonicization is a targeted borrowing: the dominant (and sometimes the subdominant) of the key whose tonic would be the tonicized chord is borrowed." },
{ q:"Which chord can replace a subdominant in a tonicization?", opts:["The secondary dominant directly (V/X)","The main tonic","The VII degree","An augmented chord"], a:0, fb:"In practice, SD → secondary D is often replaced by the direct secondary dominant. Instead of SD/X → V/X → X, one goes V/X → X. V/V can thus replace a SD chord." },
{ q:"The progression C–D7–G7–C illustrates:", opts:["A modulation to G","A tonicization of G (V) via D7 = V/V","A borrowing from C minor","A chaconne bass"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 momentarily tonicizes G — G is prepared by its own dominant before resolving to C. We never left C major." },
{ q:"The progression A–B7–E7–A in A major illustrates:", opts:["A modulation to E","A chain tonicization: B7 = V/V, E7 = V","A borrowing from A minor","A series of plagal cadences"], a:1, fb:"A (I) → B7 (V/V of A) → E7 (V of A) → A (I). B7 tonicizes E7, which in turn resolves to A. This is a chain of secondary dominants." },
{ q:"When a chord is tonicized, the reference tritone for determining functions is:", opts:["That of the main key","That of the temporary key (of the tonicized chord)","There is no tritone in a tonicization","The tritone of the VII degree"], a:1, fb:"In a tonicization, one temporarily enters the key of the tonicized chord. The functional tritone of that temporary key guides the analysis of the secondary chords' functions." },
{ q:"Tonicization can combine:", opts:["Only secondary dominants","Secondary dominants and diatonic substitutions or borrowings","Only borrowings from the parallel key","Only inversions"], a:1, fb:"The rules of harmony coexist. Within a tonicization, diatonic substitutions or borrowings may be introduced — provided the tritone of the temporary key is the reference." },
{ q:"The progression C–A7–Dm–G7–C uses A7 as:", opts:["The main dominant","V/II — dominant of Dm","A borrowing from C minor","A Neapolitan chord"], a:1, fb:"A7 = V/II in C major. It momentarily tonicizes Dm (II degree) before Dm resumes its subdominant function in the final SD–D–T progression." },
{ q:"In a tonicization, the artificial leading tone must:", opts:["Descend","Rise a half step to the root of the tonicized chord","Remain stationary","Leap a fifth"], a:1, fb:"Like the natural leading tone, the artificial leading tone rises a half step to its resolution — the root of the tonicized chord. Ex: C# → D in A7 → Dm." },

{ q:"How do you quickly calculate a secondary dominant?", opts:["Go up 4 degrees from the target chord","Go up 5 degrees (or down 4) from the target chord and play an X7 chord","Go down 3 degrees","Always use the bVII chord"], a:1, fb:"Shortcut: to tonicize X, count up 5 notes from X and play a dominant 7 chord (X7). Ex: for Dm, count D–E–F–G–A = A7. For Am: A–B–C–D–E = E7." },
{ q:"The secondary dominant always contains:", opts:["The fifth of the target chord","The artificial leading tone of the target chord — a half step below its root","The root of the main key","The major seventh"], a:1, fb:"V/X always contains the leading tone of X — a note a half step below the root of X. Ex: V/Dm = A7, which contains C# (leading tone of D, a half step below D)." },
{ q:"V/IV in C major is:", opts:["D7","G7","C7","A7"], a:2, fb:"IV of C = F. The dominant of F = C. V/IV = C7 (C–E–G–Bb). The seventh Bb (in C7) is the note that colors the tonicization of F." },
{ q:"V/III in C major is:", opts:["F7","B7","A7","E7"], a:1, fb:"III of C = Em. The dominant of Em = B. V/III = B7 (B–D#–F#–A). D# is the leading tone of E that rises to E." },
{ q:"V/VI in C major is:", opts:["D7","A7","E7","B7"], a:2, fb:"VI of C = Am. The dominant of Am = E. V/VI = E7 (E–G#–B–D). G# is the artificial leading tone of A that rises to A." },
{ q:"V/V in G major is:", opts:["C7","A7","D7","E7"], a:1, fb:"V of G = D. The dominant of D = A. V/V in G major = A7. The progression A7–D7–G in G major is a double tonicization." },
{ q:"In the progression C–E7–Am–G7–C, E7 is:", opts:["The main dominant","V/VI — it tonicizes Am","A borrowing from C minor","V/II"], a:1, fb:"E7 = V/VI in C major. It contains G# (artificial leading tone of Am) that rises to A. E7 → Am creates a secondary resolution before moving on to G7–C." },
{ q:"The characteristic accidental of V/II in C (= A7) is:", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = A–C#–E–G. C# is the third of A7 and the artificial leading tone of Dm — it rises a half step to D." },
{ q:"The characteristic accidental of V/V in C (= D7) is:", opts:["C#","F#","G#","Bb"], a:1, fb:"D7 = D–F#–A–C. F# is the third of D7 and the artificial leading tone of G — it rises a half step to G." },
{ q:"The characteristic accidental of V/VI in C (= E7) is:", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = E–G#–B–D. G# is the third of E7 and the artificial leading tone of Am — it rises a half step to A." },
{ q:"The progression C–D7–G–C differs from C–D7–G7–C because:", opts:["D7 is different","G without a seventh lacks the tritone F–B — the tension toward C is weaker","C is different","There is no harmonic difference"], a:1, fb:"G without a seventh = G major (G–B–D) — it lacks the tritone F–B, so the pull toward C is less strong. G7 with its seventh F creates the tritone B–F that resolves strongly to C." },
{ q:"V/IV tonicizes:", opts:["The dominant","The subdominant","The II degree","The VI degree"], a:1, fb:"IV = subdominant (F in C). V/IV = C7 momentarily tonicizes F before F plays its usual subdominant role." },
{ q:"In the progression A–B7–E7–A (in A major), B7 is:", opts:["The main dominant","V/V — it tonicizes E7","A borrowing from A minor","The VII degree"], a:1, fb:"V of A = E. V of E = B. B7 = V/V in A major. It tonicizes the dominant E7 before E7 resolves to A." },
{ q:"Which note is common to G7 and D7 in C major?", opts:["F","G","D","A"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F is in G7 but not in D7 (which has F#). D is in G7 as its fifth and is the root of D7. In fact there is no common note between G7 and D7 — D appears in G7 as the fifth and as the root of D7." },
{ q:"The secondary dominant of a diminished chord is:", opts:["Impossible — diminished chords cannot be tonicized","Another diminished chord","A major chord","A minor 7 chord"], a:0, fb:"Diminished chords cannot be tonicized — they cannot function as a tonic. Therefore no secondary dominant exists for diminished degrees (VII in major, II in minor)." },
{ q:"The progression Dm–A7–Dm in C major shows:", opts:["A modulation to D minor","A tonicization of Dm — A7 = V/II acts as a temporary dominant of Dm","A borrowing from D major","A plagal cadence"], a:1, fb:"A7 is V/II — it momentarily tonicizes Dm. The progression Dm–A7–Dm is a mini authentic cadence in D minor, embedded within the main key of C major." },
{ q:"In G major, V/II =", opts:["C7","D7","A7","E7"], a:2, fb:"II of G = Am. The dominant of Am = E. V/II in G major = E7." },
{ q:"In the progression C–A7–Dm–D7–G7–C, D7 is:", opts:["The dominant of C","V/V — it tonicizes G7 before G7 resolves to C","A borrowing from D major","V/II a second time"], a:1, fb:"D7 = V/V in C major. It momentarily tonicizes G7 before the final resolution G7–C. The progression contains two tonicizations: A7 (V/II) tonicizes Dm, D7 (V/V) tonicizes G7." },
{ q:"Why is V/V the most frequent tonicization?", opts:["By chance","Because G (V) is the most important chord after the tonic — reinforcing its dominant strengthens the final cadence","Because D7 is easy to play","Because it avoids the tritone"], a:1, fb:"The dominant (V) is the most crucial chord in the key. Strengthening its own dominant (V/V) further reinforces the final V–I cadence. It is the most directly functional tonicization." },
{ q:"In V/X, if X is a minor chord, the secondary dominant is:", opts:["A minor 7 chord","A dominant 7 chord (major triad with minor seventh)","A diminished chord","A major 7 chord"], a:1, fb:"The secondary dominant is always an X7 chord (major triad + minor seventh) — regardless of the nature of the tonicized chord. V/Dm = A7, V/Am = E7, V/Em = B7 — all are X7 chords." },
{ q:"The progression C–E7–Am–Dm–G7–C contains how many tonicizations?", opts:["None","Only one (E7)","Two (E7 and possibly a second)","Three"], a:1, fb:"E7 = V/VI tonicizes Am. That is the only secondary dominant in this progression. Am, Dm, G7, and C are all diatonic to C major — no additional tonicization." },
{ q:"To tonicize Bm (VII of C# major), one uses:", opts:["F#7","E7","A7","D7"], a:0, fb:"The dominant of B = F#. To tonicize Bm, one uses F#7 — regardless of the main key. The rule is universal: count up 5 notes from the target chord and play X7." },

{ q:"The neighbor keys of a key are:", opts:["The keys an octave apart","The keys that share at least 6 common notes — the first 6 degrees of the major scale and their relatives","The keys with the same key signature","The keys a fifth away"], a:1, fb:"Neighbor keys share at least 6 common notes. In C major: Dm, Em, F, G, Am and their own scales. Each degree of the scale corresponds to a neighbor key." },
{ q:"In C major, the neighbor keys are:", opts:["D major, E major, F major, G major, A major","D minor, E minor, F major, G major, A minor","B minor, C# major, D major","Gb major, Ab major"], a:1, fb:"The 6 neighbor keys of C major: Dm (II), Em (III), F (IV), G (V), Am (VI). These are the keys of the diatonic degrees — they share 6 or 7 common notes with C." },
{ q:"The secondary dominant of Am (VI of C) is:", opts:["D7","A7","E7","B7"], a:2, fb:"Am is the VI of C. The dominant of Am = E7 (E–G#–B–D). E7 = V/VI. G# is the artificial leading tone of Am." },
{ q:"The secondary subdominant of G major (V of C) is:", opts:["C7","Am7 and CMaj7","Dm7 and FMaj7","A7"], a:1, fb:"In G major, the subdominant = IV of G = C. Therefore the SD chords of G are Am7 (II of G) and CMaj7 (IV of G). These can be used to prepare D7 (V/V) in a tonicization of G." },
{ q:"In D major, V/V is:", opts:["G7","A7","E7","B7"], a:1, fb:"V of D = A. V of A = E. V/V in D major = E7. The progression E7–A7–D illustrates a double tonicization in D major." },
{ q:"The relationship between the main tonic and its neighbor keys is:", opts:["None — they are independent","Each neighbor key shares 6–7 notes with the main tonic — chords can be exchanged through tonicization or borrowing","They have the same key signature","They always have the same root"], a:1, fb:"Neighbor keys share almost all their notes with the main tonic — which is why transitions through tonicization are so smooth. One remains in a harmonically familiar territory." },
{ q:"In the neighbor-key table for D major, which neighbor key corresponds to the IV degree?", opts:["E minor","G major","A major","F# minor"], a:1, fb:"The IV degree of D major is G. G major is therefore the neighbor key corresponding to the IV degree of D. Its secondary dominant in D major = C7 (V/IV)." },
{ q:"The secondary subdominant of a neighbor key allows one to:", opts:["Tonicize the main tonic","Prepare the secondary dominant — SD/X → V/X → X","Modulate definitively","Create parallel octaves"], a:1, fb:"SD/X prepares V/X which resolves to X. Ex: to tonicize G in C: Am7 (SD/G) → D7 (V/G) → G → C. The secondary subdominant enriches the tonicization." },
{ q:"What is the secondary dominant of F major (IV of C)?", opts:["G7","D7","C7","A7"], a:2, fb:"F is the IV of C. The dominant of F = C. C7 (C–E–G–Bb) = V/IV. The seventh Bb (in C7) descends to A (third of F)." },
{ q:"In A major, the neighbor keys include:", opts:["C major and D minor","Bm, C#m, D major, E major, F#m","G major and Am","F major and Gm"], a:1, fb:"The neighbor keys of A major: Bm (II), C#m (III), D (IV), E (V), F#m (VI). These are the keys of the diatonic degrees of A major." },
{ q:"In G major, V/VI =", opts:["D7","A7","B7","C7"], a:1, fb:"VI of G = Em. Dominant of Em = B. V/VI in G major = B7 (B–D#–F#–A). D# is the artificial leading tone of Em in the key of G." },
{ q:"The progression G–A7–Dm–C–G in G major illustrates:", opts:["A modulation to D minor","A borrowing of Dm from G minor","A tonicization of Dm — Dm is the VI of G and A7 = V/VI in G major","A chaconne bass"], a:2, fb:"In G major, VI = Em. But Dm here is a borrowing from G minor (VI of G minor = Dm). A7 tonicizes Dm as if it were momentarily tonic. Contextual analysis is required." },
{ q:"How do you find the secondary dominant of Em (III of C)?", opts:["Go up 3 degrees from E = G, play G7","Go up 5 degrees from E = B, play B7","Go down 2 degrees from E = D, play D7","Play Em7 directly"], a:1, fb:"Count up 5 notes from E: E–F–G–A–B = B. Play B7 (B–D#–F#–A). B7 = V/III in C major. D# is the leading tone of E that rises to E." },
{ q:"Neighbor keys facilitate tonicizations because:", opts:["They have fewer notes","They share almost all their notes with the main key — transitions are smooth","They are lower in pitch","They have more major chords"], a:1, fb:"With 6–7 notes in common, the transition to a neighbor key is perceived as natural. A tonicization toward a neighbor key is not jarring — one remains in a familiar harmonic world." },
{ q:"In a tonicization, can V/X be combined with a Neapolitan of X?", opts:["No — the rules are mutually exclusive","Yes — all rules coexist, provided the tritone of X is the reference","Only in minor","Only with borrowings from the parallel key"], a:1, fb:"Yes. Within the temporary key of X, any harmonic tool may be used: Neapolitan of X, borrowing from X minor, diatonic substitution in X. The tritone of X is the reference." },
{ q:"In C major, which of these chords is NOT a valid secondary dominant?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (impossible diatonically)"], a:3, fb:"G#7 does not exist as a diatonic secondary dominant in C major — no diatonic chord of C has G# as the root of its dominant. A7, E7, and C7 (the correct notation for V/IV) are all valid." },
{ q:"The secondary subdominant of Dm (II of C) is:", opts:["G7","Em7b5 and Gm7","Am7 and CMaj7","D7"], a:1, fb:"In the key of D minor, the subdominant = IV of D minor = Gm. And the II of D minor = Em7b5. Therefore SD/Dm = Em7b5 (II of Dm) and Gm7 (IV of Dm)." },
{ q:"In Eb major, V/V is:", opts:["F7","Bb7","C7","G7"], a:1, fb:"V of Eb = Bb. The dominant of Bb = F. V/V in Eb = F7 — however, the correct answer among the options listed is Bb7, which is V of Eb directly, not V/V." },

{ q:"A chain of tonicizations is:", opts:["A succession of diminished chords","A sequence of secondary dominants, each tonicizing the next","A succession of authentic cadences","A circle of fifths without dominants"], a:1, fb:"A chain of tonicizations links several secondary dominants: V/V/V → V/V → V → I. Each chord prepares the next dominant, creating accumulating tension toward the final resolution." },
{ q:"The progression C–C#7–F#7–B7–E7–A in A major is:", opts:["A modulation to C#","A chain of secondary dominants: V/V/V/V–V/V/V–V/V–V–I","A mass borrowing","A diatonic circle of fifths"], a:1, fb:"C#7 = V/V/V/V of A (since C#7 → F#7 → B7 → E7 → A). Each chord tonicizes the next through a dominant-to-tonic motion. Progressive tension toward A." },
{ q:"The progression A–B7–E7–A (in A major) is a chain because:", opts:["B7 and E7 are both in the A scale","B7 tonicizes E7 (V/V) which tonicizes A (V) — two levels of secondary dominants","They are passing chords","They are borrowings from A minor"], a:1, fb:"B7 = V/V in A major (tonicizes E7). E7 = V in A (tonicizes A). Two nested levels of tonicization: V/V → V → I. Tension builds over two steps before the resolution." },
{ q:"The notation V/V/V means:", opts:["The fifth of the fifth of the fifth","The dominant of the dominant of the dominant — three levels of tonicization","A modulation in three steps","An impossible chord"], a:1, fb:"V/V/V = dominant of the dominant of the dominant. In C: V = G, V/V = D7, V/V/V = A7. The progression A7–D7–G7–C is a chain of three tonicizations." },
{ q:"In a chain, each chord resolves:", opts:["To the main tonic","To the following chord such that each chord acts as the dominant of the next","By chromatic half step","To the same chord"], a:1, fb:"In a chain V/V/V → V/V → V → I: each chord resolves to the next — A7 → D7 → G7 → C. Each resolution is a micro-cadence that reinforces the one that follows." },
{ q:"The progression C–A7–D7–G7–C contains:", opts:["No tonicization","One tonicization (A7)","Two tonicizations (A7 = V/II and D7 = V/V)","Three tonicizations"], a:2, fb:"A7 = V/II (briefly tonicizes Dm — Dm is bypassed here). D7 = V/V (tonicizes G7). Two levels of secondary dominants are chained before the final resolution G7–C." },
{ q:"Why do chains of secondary dominants create increasing tension?", opts:["Because they use dissonant chords","Because each secondary dominant reinforces the next — the final resolution is all the more satisfying","Because they modulate","Because they suppress the tritone"], a:1, fb:"Each step of the chain creates an expectation that is partially satisfied (secondary resolution) but points toward the final resolution. Tension accumulates and the final resolution is more powerful." },
{ q:"In C major, the chain V/V/V–V/V–V–I is written:", opts:["B7–E7–A7–C","A7–D7–G7–C","D7–G7–C7–F","E7–A7–Dm–G7"], a:1, fb:"V = G, V/V = D7, V/V/V = A7. The chain is A7–D7–G7–C. Each chord resolves a fifth lower, toward the final resolution on C." },
{ q:"In the progression G–C#7–F#7–B7–E7–Am–D7–G (in G major), how many tonicizations are there?", opts:["Two","Three","Four or more (complex chain)","Only one"], a:2, fb:"C#7 (V/VI of G, tonicizes F#m), F#7, B7 (V/III, tonicizes Em/E), E7 (V/II, tonicizes Am), D7 (V/V, tonicizes G) — this is a long chain with at least 4 levels of tonicization." },
{ q:"The common simplification of a tonicization is:", opts:["Never tonicize","Replace SD/X → V/X by going directly to V/X","Always use the Neapolitan","Never chain dominants"], a:1, fb:"In practice, instead of SD → secondary dominant, one jumps directly to the secondary dominant. Instead of Am → D7 → G → C, one goes directly D7 → G → C. V/V replaces the subdominant." },
{ q:"In jazz, chains of secondary dominants are called:", opts:["Ostinatos","Backcycling or dominant chain","Dominant arpeggios","Dominant pedal"], a:1, fb:"In jazz, chaining secondary dominants toward the final resolution is called 'backcycling' or a 'dominant chain.' It is the basis of many standard reharmonizations." },
{ q:"The progression I7–IV in the 12-bar blues uses I7 as:", opts:["A stable tonic chord","V/IV — tonicization of IV (the subdominant)","A borrowing from I minor","A passing chord"], a:1, fb:"In the blues, I7 (e.g. C7 in C) is V/IV — it tonicizes F (IV). C7 contains Bb which is foreign to C major but is the seventh of C7, acting as a leading tone toward F. It is a tonicization of the subdominant." },
{ q:"Can a borrowed chord be tonicized?", opts:["No — borrowed chords cannot be tonicized","Yes — any chord present in the progression can be tonicized, even a borrowed chord","Only in minor","Only if the borrowing is the IV degree"], a:1, fb:"A borrowed chord can be tonicized — its own dominant is applied to it. Ex: if Ab (bVI of C) is borrowed from C minor, it can be tonicized with Eb7 (V of Ab) to reinforce the borrowing." },
{ q:"The progression C–Eb7–Ab–G7–C contains:", opts:["Only borrowings","A borrowing (Ab) and a tonicization of that borrowing (Eb7 = V/bVI)","Two modulations","A circle of fifths"], a:1, fb:"Ab is borrowed from C minor (bVI). Eb7 is V/Ab — it tonicizes the borrowed chord before G7 brings the music back to C. Borrowing and tonicization coexist in the same progression." },
{ q:"The chain A7–D7–G7–C in C major can be analyzed as:", opts:["Three successive modulations","V/II–V/V–V–I: tonicization of Dm (bypassed), tonicization of G, authentic cadence","Three borrowings without function","A standard diatonic circle of fifths"], a:1, fb:"A7 = V/II (prepares D, but D is bypassed — A7 resolves directly to D7 without waiting for Dm). D7 = V/V. G7 = V. C = I. Three nested levels of tonicization." },
{ q:"In the chain E7–A7–D7–G7–C, how many secondary resolutions are there before the final resolution?", opts:["None","Two","Three","Four"], a:2, fb:"E7→A7 (secondary resolution 1), A7→D7 (secondary resolution 2), D7→G7 (secondary resolution 3), G7→C (final resolution). Three secondary resolutions, one final." },
{ q:"Tonicizing a tonicization means:", opts:["Repeating the same note","Applying a new secondary dominant to an already-present secondary dominant","Modulating twice in a row","Using two borrowings"], a:1, fb:"One can tonicize a tonicization: apply a secondary dominant to a secondary dominant. V/V/V tonicizes V/V. The chain can theoretically be extended indefinitely." },
{ q:"The jazz progression ii–V–I–ii–V–I in a 'loop' illustrates:", opts:["A repeated modulation","The fundamental functional cycle T–SD–D–T repeated, sometimes with internal tonicizations","A dominant pedal sequence","Four-voice counterpoint"], a:1, fb:"ii–V–I = SD–D–T = the functional cycle. In jazz, each V can be enriched with a chain of secondary dominants (ii/V → V/V → V → I) to densify the harmony." },

{ q:"What is the artificial leading tone of V/V in F major?", opts:["B natural","E natural","C#","A#"], a:0, fb:"V of F = C. V/V in F = G7. G7 = G–B–D–F. B natural is the artificial leading tone of C — it rises a half step to C. Note: F major has Bb, so B natural is indeed an artificial accidental." },
];

const questionsEs: Question[] = [{ q:"La tonicización consiste en:", opts:["Modular definitivamente a una nueva tonalidad","Tratar un acorde como tónica temporal y precederlo de su dominante","Suprimir la tónica principal","Tocar todos los acordes en menor"], a:1, fb:"La tonicización convierte temporalmente un acorde en 'tónica' aplicándole sus propios acordes funcionales — en particular su dominante propia. No es una modulación — se permanece en la tonalidad principal." },
{ q:"¿Cuál es la diferencia entre tonicización y modulación?", opts:["Son idénticas","La tonicización es momentánea, la modulación establece duraderamente una nueva tonalidad","La modulación es más corta","La tonicización utiliza préstamos"], a:1, fb:"Tonicización: un acorde desempeña el papel de tónica por un instante. Modulación: se cambia realmente de tonalidad principal — confirmado por una cadencia perfecta en el nuevo centro." },
{ q:"¿Qué acorde puede ser tonicizado?", opts:["Únicamente la tónica principal","Todo acorde diatónico excepto la tónica principal y los acordes disminuidos","Únicamente los acordes mayores","Únicamente las dominantes"], a:1, fb:"Todo acorde diatónico puede ser tonicizado — excepto la tónica principal (ya es tónica) y los acordes disminuidos (demasiado inestables para desempeñar el papel de tónica)." },
{ q:"¿Por qué la tónica principal no puede ser tonicizada?", opts:["Por convención","Porque ya es la tónica — no hace falta 'convertirla' en tónica","Porque es demasiado grave","Porque no tiene dominante"], a:1, fb:"La tónica principal ya es el centro tonal de la escala — no necesita ser reforzada por su propia dominante. Tonicizarla sería una tautología armónica." },
{ q:"¿Por qué los acordes disminuidos no pueden ser tonicizados?", opts:["Porque son demasiado inestables para asumir la función de tónica","Porque son raros","Porque tienen una quinta justa","Porque siempre están en inversión"], a:0, fb:"Los acordes disminuidos son intrínsecamente inestables — su quinta disminuida impide cualquier sensación de reposo o estabilidad. Sirven como tensiones, no como puntos de llegada." },
{ q:"La notación V/V significa:", opts:["La quinta de la quinta","La dominante de la dominante — el acorde V7 de la tonalidad de V","La subdominante de V","La dominante dividida entre dos"], a:1, fb:"V/V = dominante de la dominante. En C mayor: V = G, por lo tanto V/V = D7. D7 toniciza G antes de que G resuelva sobre C." },
{ q:"La dominante secundaria V/V en C mayor es:", opts:["C7","A7","D7","E7"], a:2, fb:"V de C = G. La dominante de G es D7. D7 → G7 → C = V/V–V–I. D7 contiene F# (sensible de G) que asciende hacia G." },
{ q:"La sensible artificial creada por una tonicización es:", opts:["Una nota de la escala principal","Una alteración (sostenido o becuadro) que crea un semitono ascendente hacia el grado tonicizado","Un bordado","Un retardo"], a:1, fb:"Para tonicizar un acorde, se crea una sensible artificial — una alteración (a menudo un sostenido) que asciende un semitono hacia la fundamental del acorde objetivo. Ej.: C# asciende hacia D en V/II." },
{ q:"En C mayor, tonicizar Am (VIº) requiere el acorde:", opts:["D7","A7","E7","B7"], a:2, fb:"Am es el VIº de C. Su dominante propia es E7 (Mi–Sol#–Si–Re). E7 → Am. El Sol# es la sensible artificial que asciende hacia La." },
{ q:"En C mayor, V/II se escribe:", opts:["D7","A7","E7","B7"], a:1, fb:"II de C = Dm. La dominante de D = A. V/II = A7 (La–Do#–Mi–Sol). El Do# es la sensible de D que asciende hacia Re." },
{ q:"La tonicización es una forma de préstamo porque:", opts:["Cambia la tonalidad principal","Toma prestados temporalmente acordes de otra tonalidad — la tonalidad del acorde tonicizado","Suprime grados","Ignora el tritono"], a:1, fb:"La tonicización es un préstamo dirigido: se toma prestada la dominante (y a veces la subdominante) de la tonalidad cuya tónica sería el acorde tonicizado." },
{ q:"¿Qué acorde puede reemplazar una subdominante en una tonicización?", opts:["La dominante secundaria directamente (V/X)","La tónica principal","El VIIº grado","Un acorde aumentado"], a:0, fb:"En la práctica, a menudo se reemplaza SD → D secundaria por la dominante secundaria directa. En lugar de SD/X → V/X → X, se hace V/X → X. V/V puede así reemplazar un acorde de SD." },
{ q:"La progresión C–D7–G7–C ilustra:", opts:["Una modulación en G","Una tonicización de G (V) mediante D7 = V/V","Un préstamo a C menor","Un bajo de chacona"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 toniciza G momentáneamente — G es preparado por su propia dominante antes de resolver sobre C. Nunca se abandonó C mayor." },
{ q:"La progresión A–B7–E7–A en A mayor ilustra:", opts:["Una modulación en E","Una tonicización en cadena: B7 = V/V, E7 = V","Un préstamo a A menor","Una serie de cadencias plagales"], a:1, fb:"A (I) → B7 (V/V de A) → E7 (V de A) → A (I). B7 toniciza E7, que a su vez resuelve sobre A. Es una cadena de dominantes secundarias." },
{ q:"Cuando se toniciza un acorde, el tritono de referencia para determinar las funciones es:", opts:["El de la tonalidad principal","El de la tonalidad temporal (del acorde tonicizado)","No hay tritono en una tonicización","El tritono del VIIº grado"], a:1, fb:"En una tonicización, se entra temporalmente en la tonalidad del acorde tonicizado. El tritono funcional de esa tonalidad temporal guía el análisis de las funciones de los acordes secundarios." },
{ q:"La tonicización puede combinar:", opts:["Únicamente dominantes secundarias","Dominantes secundarias y sustituciones diatónicas o préstamos","Únicamente préstamos del homónimo","Únicamente inversiones"], a:1, fb:"Las reglas de la armonía coexisten. En una tonicización, se pueden introducir sustituciones diatónicas o préstamos — siempre que se tome como referencia el tritono de la tonalidad temporal." },
{ q:"La progresión C–A7–Dm–G7–C usa A7 como:", opts:["Dominante principal","V/II — dominante de Dm","Préstamo a C menor","Acorde napolitano"], a:1, fb:"A7 = V/II en C mayor. Toniciza Dm (IIº grado) momentáneamente antes de que Dm retome su función de subdominante en la progresión SD–D–T final." },
{ q:"En una tonicización, la sensible artificial debe:", opts:["Descender","Ascender un semitono hacia la fundamental del acorde tonicizado","Permanecer inmóvil","Saltar una quinta"], a:1, fb:"Como la sensible natural, la sensible artificial asciende un semitono hacia su resolución — la fundamental del acorde tonicizado. Ej.: C# → D en A7 → Dm." },
{ q:"¿Cómo calcular rápidamente una dominante secundaria?", opts:["Subir 4 grados desde el acorde objetivo","Subir 5 grados (o bajar 4) desde el acorde objetivo y tocar un acorde X7","Bajar 3 grados","Usar siempre el acorde bVII"], a:1, fb:"Truco: para tonicizar X, sube 5 notas desde X y toca un acorde de dominante 7 (X7). Ej.: para Dm, cuenta D–E–F–G–A = A7. Para Am: A–B–C–D–E = E7." },
{ q:"La dominante secundaria contiene siempre:", opts:["La quinta del acorde objetivo","La sensible artificial del acorde objetivo — un semitono por debajo de su fundamental","La fundamental de la tonalidad principal","La séptima mayor"], a:1, fb:"V/X contiene siempre la sensible de X — una nota un semitono por debajo de la fundamental de X. Ej.: V/Dm = A7, que contiene C# (sensible de D, un semitono bajo D)." },
{ q:"V/IV en C mayor es:", opts:["D7","G7","C7","A7"], a:2, fb:"IV de C = F. La dominante de F = C. V/IV = C7 (Do–Mi–Sol–Si♭). La séptima Si♭ en C7 es la nota que colorea la tonicización de F." },
{ q:"V/III en C mayor es:", opts:["F7","B7","A7","E7"], a:1, fb:"III de C = Em. La dominante de Em = B. V/III = B7 (Si–Re#–Fa#–La). El Re# es la sensible de E que asciende hacia Mi." },
{ q:"V/VI en C mayor es:", opts:["D7","A7","E7","B7"], a:2, fb:"VI de C = Am. La dominante de Am = E. V/VI = E7 (Mi–Sol#–Si–Re). El Sol# es la sensible artificial de A que asciende hacia La." },
{ q:"V/V en G mayor es:", opts:["C7","A7","D7","E7"], a:1, fb:"V de G = D. La dominante de D = A. V/V en G mayor = A7. La progresión A7–D7–G en G mayor es una doble tonicización." },
{ q:"En la progresión C–E7–Am–G7–C, E7 es:", opts:["La dominante principal","V/VI — toniciza Am","Un préstamo a C menor","V/II"], a:1, fb:"E7 = V/VI en C mayor. Contiene Sol# (sensible artificial de Am) que asciende hacia La. E7 → Am crea una resolución secundaria antes de continuar hacia G7–C." },
{ q:"La alteración característica de V/II en C (= A7) es:", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = La–Do#–Mi–Sol. El Do# (C#) es la tercera de A7 y la sensible artificial de Dm — asciende un semitono hacia Re." },
{ q:"La alteración característica de V/V en C (= D7) es:", opts:["C#","F#","G#","B♭"], a:1, fb:"D7 = Re–Fa#–La–Do. El Fa# (F#) es la tercera de D7 y la sensible artificial de G — asciende un semitono hacia Sol." },
{ q:"La alteración característica de V/VI en C (= E7) es:", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = Mi–Sol#–Si–Re. El Sol# (G#) es la tercera de E7 y la sensible artificial de Am — asciende un semitono hacia La." },
{ q:"La progresión C–D7–G–C es diferente de C–D7–G7–C porque:", opts:["D7 es diferente","G sin séptima no tiene el tritono F–B — la tensión hacia C es más débil","C es diferente","No hay diferencia armónica"], a:1, fb:"G sin séptima = G mayor (G–B–D) — no tiene el tritono F–B, por lo que la tensión hacia C es menos fuerte. G7 con su séptima F crea el tritono B–F que resuelve con fuerza hacia C." },
{ q:"V/IV toniciza:", opts:["La dominante","La subdominante","El IIº grado","El VIº grado"], a:1, fb:"IV = subdominante (F en C). V/IV = C7 toniciza F momentáneamente antes de que F desempeñe su papel habitual de subdominante." },
{ q:"En la progresión A–B7–E7–A (en A mayor), B7 es:", opts:["La dominante principal","V/V — toniciza E7","Un préstamo a A menor","El VIIº grado"], a:1, fb:"V de A = E. V de E = B. B7 = V/V en A mayor. Toniciza la dominante E7 antes de que E7 resuelva sobre A." },
{ q:"¿Qué nota es común a G7 y D7 en C mayor?", opts:["F (Fa)","G (Sol)","D (Re)","A (La)"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F (Fa) está en G7 pero no en D7 (que tiene F#). La nota común es D. En realidad no hay ninguna nota común entre G7 y D7 — D aparece en G7 como quinta y como fundamental de D7." },
{ q:"La dominante secundaria de un acorde disminuido es:", opts:["Imposible — los disminuidos no pueden ser tonicizados","Otro acorde disminuido","Un acorde mayor","Un acorde menor 7"], a:0, fb:"Los acordes disminuidos no pueden ser tonicizados — no pueden desempeñar el papel de tónica. Por lo tanto no existe dominante secundaria para los grados disminuidos (VII en mayor, II en menor)." },
{ q:"La progresión Dm–A7–Dm en C mayor muestra:", opts:["Una modulación en D menor","Una tonicización de Dm — A7 = V/II actúa como dominante temporal de Dm","Un préstamo a D mayor","Una cadencia plagal"], a:1, fb:"A7 es V/II — toniciza Dm momentáneamente. La progresión Dm–A7–Dm es una mini cadencia perfecta en D menor, incrustada en la tonalidad principal de C mayor." },
{ q:"En G mayor, V/II =", opts:["C7","D7","A7","E7"], a:2, fb:"II de G = Am. La dominante de Am = E. V/II en G mayor = E7." },
{ q:"En C–A7–Dm–D7–G7–C, D7 es:", opts:["La dominante de C","V/V — toniciza G7 antes de que G7 resuelva sobre C","Un préstamo a D mayor","V/II una segunda vez"], a:1, fb:"D7 = V/V en C mayor. Toniciza G7 momentáneamente antes de la resolución final G7–C. La progresión contiene dos tonicizaciones: A7 (V/II) toniciza Dm, D7 (V/V) toniciza G7." },
{ q:"¿Por qué V/V es la tonicización más frecuente?", opts:["Por casualidad","Porque G (V) es el acorde más importante después de la tónica — reforzar su dominante refuerza la cadencia final","Porque D7 es fácil de tocar","Porque evita el tritono"], a:1, fb:"La dominante (V) es el acorde más crucial de la tonalidad. Reforzar su propia dominante (V/V) refuerza la cadencia final V–I. Es la tonicización más directamente funcional." },
{ q:"En V/X, si X es un acorde menor, la dominante secundaria es:", opts:["Un acorde menor 7","Un acorde de dominante 7 (mayor con 7ª menor)","Un acorde disminuido","Un acorde mayor 7"], a:1, fb:"La dominante secundaria es siempre un acorde X7 (tríada mayor + 7ª menor) — independientemente de la naturaleza del acorde tonicizado. V/Dm = A7, V/Am = E7, V/Em = B7 — todos son X7." },
{ q:"La progresión C–E7–Am–Dm–G7–C contiene ¿cuántas tonicizaciones?", opts:["Ninguna","Solo una (E7)","Dos (E7 y eventualmente una segunda)","Tres"], a:1, fb:"E7 = V/VI toniciza Am. Es la única dominante secundaria en esta progresión. Am, Dm, G7 y C son todos diatónicos a C mayor — no hay tonicización adicional." },
{ q:"Para tonicizar Bm (VII de C# mayor), se utiliza:", opts:["F#7","E7","A7","D7"], a:0, fb:"La dominante de B = F#. Para tonicizar Bm, se utiliza F#7 — independientemente de la tonalidad principal. La regla es universal: sube 5 notas desde el acorde objetivo y toca X7." },
{ q:"Los tonos vecinos de una tonalidad son:", opts:["Las tonalidades a la octava","Las tonalidades que comparten al menos 6 notas comunes — los 6 primeros grados de la escala mayor y sus relativos","Las tonalidades con la misma armadura","Las tonalidades a la quinta"], a:1, fb:"Los tonos vecinos comparten al menos 6 notas comunes. En C mayor: Dm, Em, F, G, Am y su propia escala. Cada grado de la escala corresponde a un tono vecino." },
{ q:"En C mayor, los tonos vecinos son:", opts:["D mayor, E mayor, F mayor, G mayor, A mayor","D menor, E menor, F mayor, G mayor, A menor","B menor, C# mayor, D mayor","G♭ mayor, A♭ mayor"], a:1, fb:"Los 6 tonos vecinos de C mayor: Dm (II), Em (III), F (IV), G (V), Am (VI). Son las tonalidades de los grados diatónicos — comparten 6 o 7 notas comunes con C." },
{ q:"La dominante secundaria de Am (VIº de C) es:", opts:["D7","A7","E7","B7"], a:2, fb:"Am es el VIº de C. La dominante de Am = E7 (Mi–Sol#–Si–Re). E7 = V/VI. Sol# es la sensible artificial de Am." },
{ q:"La subdominante secundaria de G mayor (Vº de C) es:", opts:["C7","Am7 y CMaj7","Dm7 y FMaj7","A7"], a:1, fb:"En G mayor, la subdominante = IV de G = C. Por lo tanto los acordes SD de G son Am7 (II de G) y CMaj7 (IV de G). Se pueden usar para preparar D7 (V/V) en una tonicización de G." },
{ q:"En D mayor, V/V es:", opts:["G7","A7","E7","B7"], a:1, fb:"V de D = A. V de A = E. V/V en D mayor = E7. La progresión E7–A7–D ilustra una doble tonicización en D mayor." },
{ q:"La relación entre la tónica principal y sus tonos vecinos es:", opts:["Ninguna — son independientes","Cada tono vecino comparte 6-7 notas con la tónica — los acordes pueden intercambiarse mediante tonicización o préstamo","Tienen la misma armadura","Siempre tienen la misma fundamental"], a:1, fb:"Los tonos vecinos comparten casi todas sus notas con la tónica principal — por eso las transiciones mediante tonicización son tan fluidas. Se permanece en un territorio armónico familiar." },
{ q:"En la tabla de tonos vecinos de D mayor, ¿cuál es el tono vecino correspondiente al IVº grado?", opts:["E menor","G mayor","A mayor","F# menor"], a:1, fb:"El IVº grado de D mayor es G. G mayor es por lo tanto el tono vecino correspondiente al IVº grado de D. Su dominante secundaria en D mayor = C7 (V/IV)." },
{ q:"La subdominante secundaria de un tono vecino permite:", opts:["Tonicizar la tónica principal","Preparar la dominante secundaria — SD/X → V/X → X","Modular definitivamente","Crear octavas paralelas"], a:1, fb:"SD/X prepara V/X que resuelve sobre X. Ej.: para tonicizar G en C: Am7 (SD/G) → D7 (V/G) → G → C. La subdominante secundaria enriquece la tonicización." },
{ q:"¿Cuál es la dominante secundaria de F mayor (IVº de C)?", opts:["G7","D7","C7","A7"], a:2, fb:"F es el IVº de C. La dominante de F = C. C7 (Do–Mi–Sol–Si♭) = V/IV. La Si♭ es la séptima de C7 que desciende hacia La (tercera de F)." },
{ q:"En A mayor, los tonos vecinos incluyen:", opts:["C mayor y D menor","Bm, C#m, D mayor, E mayor, F#m","G mayor y Am","F mayor y Gm"], a:1, fb:"Los tonos vecinos de A mayor: Bm (II), C#m (III), D (IV), E (V), F#m (VI). Son las tonalidades de los grados diatónicos de A mayor." },
{ q:"En G mayor, V/VI =", opts:["D7","A7","B7","C7"], a:1, fb:"VI de G = Em. Dominante de Em = B. V/VI en G mayor = B7 (Si–Re#–Fa#–La). Re# es la sensible artificial de Em en la tonalidad de G." },
{ q:"La progresión G–A7–Dm–C–G en G mayor ilustra:", opts:["Una modulación en D menor","Un préstamo de Dm desde G menor","Una tonicización de Dm — Dm es el VIº de G y A7 = V/VI en G mayor","Un bajo de chacona"], a:2, fb:"En G mayor, VI = Em. Pero Dm aquí es un préstamo a G menor (VIº de G menor = Dm). A7 toniciza Dm como si fuera momentáneamente tónica. Se requiere análisis contextual." },
{ q:"¿Cómo encontrar la dominante secundaria de Em (IIIº de C)?", opts:["Subir 3 grados desde E = G, tocar G7","Subir 5 grados desde E = B, tocar B7","Bajar 2 grados desde E = D, tocar D7","Tocar Em7 directamente"], a:1, fb:"Sube 5 notas desde E: E–F–G–A–B = B. Toca B7 (Si–Re#–Fa#–La). B7 = V/III en C mayor. Re# es la sensible de E que asciende hacia Mi." },
{ q:"Los tonos vecinos facilitan las tonicizaciones porque:", opts:["Tienen menos notas","Comparten casi todas sus notas con la tonalidad principal — las transiciones son fluidas","Son más graves","Tienen más acordes mayores"], a:1, fb:"Con 6-7 notas comunes, la transición hacia un tono vecino se percibe como natural. Una tonicización hacia un tono vecino no resulta extraña — se permanece en un universo familiar." },
{ q:"En una tonicización, ¿se puede combinar V/X con un napolitano de X?", opts:["No — las reglas se excluyen","Sí — todas las reglas coexisten, siempre que se tome como referencia el tritono de X","Únicamente en menor","Solo con préstamos del homónimo"], a:1, fb:"Sí. En la tonalidad temporal de X, se puede utilizar cualquier herramienta armónica: napolitano de X, préstamo a X menor, sustitución diatónica en X. El tritono de X es la referencia." },
{ q:"En C mayor, ¿cuál de estos acordes NO es una dominante secundaria válida?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (imposible diatónicamente)"], a:3, fb:"G#7 no existe como dominante secundaria diatónica en C mayor — ningún acorde diatónico de C tiene G# como fundamental de su dominante. A7, E7 y F7 (= C7 es la notación correcta) son válidos." },
{ q:"La subdominante secundaria de Dm (IIº de C) es:", opts:["G7","Em7b5 y Gm7","Am7 y CMaj7","D7"], a:1, fb:"En la tonalidad de D menor, la subdominante = IV de D menor = Gm. Pero el IIº de D menor = Em7b5. Por lo tanto SD/Dm = Em7b5 (II de Dm) y Gm7 (IV de Dm)." },
{ q:"En E♭ mayor, V/V es:", opts:["F7","B♭7","C7","G7"], a:1, fb:"V de Eb = Bb. La dominante de Bb = F. V/V en Eb = F7 — espera, no. V de Eb = Bb. V de Bb = F. V/V en Eb = F7. Aquí la respuesta correcta es F7, pero las opciones proponen Bb7 — que es V de Eb directamente, no V/V." },
{ q:"Una cadena de tonicizaciones es:", opts:["Una sucesión de acordes disminuidos","Una serie de dominantes secundarias, cada una tonicizando a la siguiente","Una serie de cadencias perfectas","Un ciclo de quintas sin dominantes"], a:1, fb:"Una cadena de tonicizaciones encadena varias dominantes secundarias: V/V/V → V/V → V → I. Cada acorde prepara la dominante siguiente, creando una tensión que se acumula hacia la resolución final." },
{ q:"La progresión C–C#7–F#7–B7–E7–A en A mayor es:", opts:["Una modulación en C#","Una cadena de dominantes secundarias: V/V/V/V–V/V/V–V/V–V–I","Un préstamo masivo","Un ciclo de quintas diatónicas"], a:1, fb:"C#7 = V/V/V/V de A (ya que C#7 → F#7 → B7 → E7 → A). Cada acorde toniciza al siguiente mediante un movimiento de dominante a tónica. Tensión progresiva hacia A." },
{ q:"La progresión A–B7–E7–A (en A mayor) es una cadena porque:", opts:["B7 y E7 están ambos en la escala de A","B7 toniciza E7 (V/V) que toniciza A (V) — dos niveles de dominantes secundarias","Son acordes de paso","Son préstamos a A menor"], a:1, fb:"B7 = V/V en A mayor (toniciza E7). E7 = V en A (toniciza A). Dos niveles de tonicización encajados: V/V → V → I. La tensión sube en dos etapas antes de la resolución." },
{ q:"La notación V/V/V significa:", opts:["La quinta de la quinta de la quinta","La dominante de la dominante de la dominante — tres niveles de tonicización","Una modulación en tres etapas","Un acorde imposible"], a:1, fb:"V/V/V = dominante de la dominante de la dominante. En C: V = G, V/V = D7, V/V/V = A7. La progresión A7–D7–G7–C es una cadena de tres tonicizaciones." },
{ q:"En una cadena, cada acorde resuelve:", opts:["Sobre la tónica principal","Sobre el acorde siguiente de modo que cada acorde actúa como dominante del siguiente","Por semitono cromático","Sobre el mismo acorde"], a:1, fb:"En una cadena V/V/V → V/V → V → I: cada acorde resuelve sobre el siguiente — A7 → D7 → G7 → C. Cada resolución es una microcadencia que refuerza la siguiente." },
{ q:"La progresión C–A7–D7–G7–C contiene:", opts:["Ninguna tonicización","Una tonicización (A7)","Dos tonicizaciones (A7 = V/II y D7 = V/V)","Tres tonicizaciones"], a:2, fb:"A7 = V/II (toniciza Dm brevemente — Dm es 'esquivado' aquí). D7 = V/V (toniciza G7). Dos niveles de dominantes secundarias se encadenan antes de la resolución final G7–C." },
{ q:"¿Por qué las cadenas de dominantes secundarias crean una tensión creciente?", opts:["Porque utilizan acordes disonantes","Porque cada dominante secundaria refuerza a la siguiente — la resolución final es tanto más satisfactoria","Porque modulan","Porque suprimen el tritono"], a:1, fb:"Cada etapa de la cadena crea una expectativa que se satisface parcialmente (resolución secundaria) pero apunta hacia la resolución final. La tensión se acumula y la resolución final es más poderosa." },
{ q:"En C mayor, la cadena V/V/V–V/V–V–I se escribe:", opts:["B7–E7–A7–C","A7–D7–G7–C","D7–G7–C7–F","E7–A7–Dm–G7"], a:1, fb:"V = G, V/V = D7, V/V/V = A7. La cadena es A7–D7–G7–C. Cada acorde resuelve una quinta más abajo, hacia la resolución final sobre C." },
{ q:"En la progresión G–C#7–F#7–B7–E7–Am–D7–G (en G mayor), ¿cuántas tonicizaciones hay?", opts:["Dos","Tres","Cuatro o más (cadena compleja)","Solo una"], a:2, fb:"C#7 (V/VI de G, toniciza F#m), F#7 (V/VI ?), B7 (V/III, toniciza Em/E), E7 (V/II, toniciza Am), D7 (V/V, toniciza G) — es una larga cadena con al menos 4 niveles de tonicización." },
];

const questionsDe: Question[] = [{ q:"Die Tonikalisierung besteht darin:", opts:["Endgültig in eine neue Tonart zu modulieren","Einen Akkord als temporäre Tonika zu behandeln und ihm seine Dominante voranzustellen","Die Haupttonika zu entfernen","Alle Akkorde in Moll zu spielen"], a:1, fb:"Die Tonikalisierung macht einen Akkord vorübergehend zur 'Tonika', indem man ihm seine eigenen Funktionsakkorde – insbesondere seine eigene Dominante – voranstellt. Es handelt sich nicht um eine Modulation – man bleibt in der Haupttonart." },
{ q:"Was ist der Unterschied zwischen Tonikalisierung und Modulation?", opts:["Sie sind identisch","Die Tonikalisierung ist momentan, die Modulation etabliert dauerhaft eine neue Tonart","Die Modulation ist kürzer","Die Tonikalisierung verwendet Entlehnungen"], a:1, fb:"Tonikalisierung: Ein Akkord übernimmt nur für einen Moment die Rolle der Tonika. Modulation: Man wechselt wirklich die Haupttonart – bestätigt durch eine vollständige Kadenz im neuen Zentrum." },
{ q:"Welcher Akkord kann tonikalisiert werden?", opts:["Nur die Haupttonika","Jeder diatonische Akkord außer der Haupttonika und den verminderten Akkorden","Nur Dur-Akkorde","Nur Dominanten"], a:1, fb:"Jeder diatonische Akkord kann tonikalisiert werden – außer der Haupttonika (bereits Tonika) und den verminderten Akkorden (zu instabil, um eine Tonika-Funktion zu übernehmen)." },
{ q:"Warum kann die Haupttonika nicht tonikalisiert werden?", opts:["Per Konvention","Weil sie bereits die Tonika ist – sie muss nicht erst 'zur Tonika gemacht' werden","Weil sie zu tief liegt","Weil sie keine Dominante hat"], a:1, fb:"Die Haupttonika ist bereits das tonale Zentrum der Tonleiter – sie muss nicht durch ihre eigene Dominante gestärkt werden. Sie zu tonikalisieren wäre eine harmonische Tautologie." },
{ q:"Warum können verminderte Akkorde nicht tonikalisiert werden?", opts:["Weil sie zu instabil sind, um die Tonika-Funktion zu übernehmen","Weil sie selten sind","Weil sie eine reine Quinte haben","Weil sie immer umgekehrt sind"], a:0, fb:"Verminderte Akkorde sind von Natur aus instabil – ihre verminderte Quinte verhindert jedes Gefühl von Ruhe oder Stabilität. Sie dienen als Spannungsakkorde, nicht als Zielpunkte." },
{ q:"Die Notation V/V bedeutet:", opts:["Die Quinte der Quinte","Die Dominante der Dominante – der V7-Akkord der Tonart von V","Die Subdominante von V","Die Dominante geteilt durch zwei"], a:1, fb:"V/V = Dominante der Dominante. In C-Dur: V = G, also V/V = D7. D7 tonikalisiert G, bevor G auf C auflöst." },
{ q:"Die Sekundärdominante V/V in C-Dur ist:", opts:["C7","A7","D7","E7"], a:2, fb:"V von C = G. Die Dominante von G ist D7. D7 → G7 → C = V/V–V–I. D7 enthält F# (Leitton von G), der nach G aufsteigt." },
{ q:"Der künstliche Leitton, der durch eine Tonikalisierung entsteht, ist:", opts:["Eine Note der Haupttonleiter","Eine Alteration (Kreuz oder Auflösungszeichen), die einen Halbtonschritt aufwärts zum tonikaliserten Grad erzeugt","Eine Wechselnote","Ein Vorhalt"], a:1, fb:"Um einen Akkord zu tonikalisieren, erzeugt man einen künstlichen Leitton – eine Alteration (oft ein Kreuz), die einen Halbton aufwärts zur Grundnote des Zielakkords führt. Z. B.: C# steigt nach D in V/II." },
{ q:"In C-Dur erfordert die Tonikalisierung von Am (VI.) den Akkord:", opts:["D7","A7","E7","B7"], a:2, fb:"Am ist die VI. Stufe von C. Seine eigene Dominante ist E7 (E–G#–B–D). E7 → Am. Das G# ist der künstliche Leitton, der nach A aufsteigt." },
{ q:"In C-Dur schreibt sich V/II:", opts:["D7","A7","E7","B7"], a:1, fb:"II. von C = Dm. Die Dominante von D = A. V/II = A7 (A–C#–E–G). Das C# ist der Leitton von D, der nach D aufsteigt." },
{ q:"Die Tonikalisierung ist eine Form der Entlehnung, weil:", opts:["Sie die Haupttonart ändert","Sie vorübergehend Akkorde aus einer anderen Tonart entlehnt – der Tonart des tonikaliserten Akkords","Sie Stufen auslässt","Sie den Tritonus ignoriert"], a:1, fb:"Die Tonikalisierung ist eine gezielte Entlehnung: Man entlehnt die Dominante (und manchmal die Subdominante) der Tonart, deren Tonika der tonikaliserte Akkord wäre." },
{ q:"Welcher Akkord kann eine Subdominante in einer Tonikalisierung ersetzen?", opts:["Die Sekundärdominante direkt (V/X)","Die Haupttonika","Die VII. Stufe","Ein übermäßiger Akkord"], a:0, fb:"In der Praxis ersetzt man SD → Sekundärdominante oft durch die direkte Sekundärdominante. Anstatt SD/X → V/X → X macht man V/X → X. V/V kann so einen SD-Akkord ersetzen." },
{ q:"Die Progression C–D7–G7–C illustriert:", opts:["Eine Modulation nach G","Eine Tonikalisierung von G (V) durch D7 = V/V","Eine Entlehnung aus C-Moll","Eine Chaconne-Basslinie"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 tonikalisiert G vorübergehend – G wird durch seine eigene Dominante vorbereitet, bevor es auf C auflöst. C-Dur wurde nie verlassen." },
{ q:"Die Progression A–B7–E7–A in A-Dur illustriert:", opts:["Eine Modulation nach E","Eine Kettentonikalisierung: B7 = V/V, E7 = V","Eine Entlehnung aus A-Moll","Eine Folge von Plagalkadenzen"], a:1, fb:"A (I) → B7 (V/V von A) → E7 (V von A) → A (I). B7 tonikalisiert E7, das seinerseits auf A auflöst. Es handelt sich um eine Kette von Sekundärdominanten." },
{ q:"Wenn man einen Akkord tonikalisiert, ist der maßgebliche Tritonus für die Funktionsbestimmung:", opts:["Der der Haupttonart","Der der temporären Tonart (des tonikaliserten Akkords)","Es gibt keinen Tritonus in einer Tonikalisierung","Der Tritonus der VII. Stufe"], a:1, fb:"Bei einer Tonikalisierung tritt man vorübergehend in die Tonart des tonikaliserten Akkords ein. Der funktionale Tritonus dieser temporären Tonart leitet die Analyse der Funktionen der Sekundärakkorde." },
{ q:"Die Tonikalisierung kann kombinieren:", opts:["Nur Sekundärdominanten","Sekundärdominanten und diatonische Substitutionen oder Entlehnungen","Nur Entlehnungen aus der gleichnamigen Tonart","Nur Umkehrungen"], a:1, fb:"Die Regeln der Harmonik koexistieren. In einer Tonikalisierung kann man diatonische Substitutionen oder Entlehnungen einführen – vorausgesetzt, man bezieht sich auf den Tritonus der temporären Tonart." },
{ q:"Die Progression C–A7–Dm–G7–C verwendet A7 als:", opts:["Hauptdominante","V/II – Dominante von Dm","Entlehnung aus C-Moll","Neapolitanischen Akkord"], a:1, fb:"A7 = V/II in C-Dur. Er tonikalisiert Dm (II. Stufe) vorübergehend, bevor Dm seine Subdominantfunktion in der abschließenden SD–D–T-Progression wieder aufnimmt." },
{ q:"In einer Tonikalisierung muss der künstliche Leitton:", opts:["Absteigen","Einen Halbton aufwärts zur Grundnote des tonikaliserten Akkords steigen","Stehen bleiben","Eine Quinte springen"], a:1, fb:"Wie der natürliche Leitton steigt der künstliche Leitton einen Halbton aufwärts zu seiner Auflösung – der Grundnote des tonikaliserten Akkords. Z. B.: C# → D in A7 → Dm." },
{ q:"Wie berechnet man schnell eine Sekundärdominante?", opts:["Von der Zielakkordgrundnote 4 Stufen aufsteigen","Von der Zielakkordgrundnote 5 Stufen aufsteigen (oder 4 absteigen) und einen X7-Akkord spielen","3 Stufen absteigen","Immer den bVII-Akkord verwenden"], a:1, fb:"Tipp: Um X zu tonikalisieren, zähle 5 Noten von X aufwärts und spiele einen Dominantseptakkord (X7). Z. B.: für Dm: D–E–F–G–A = A7. Für Am: A–B–C–D–E = E7." },
{ q:"Die Sekundärdominante enthält immer:", opts:["Die Quinte des Zielakkords","Den künstlichen Leitton des Zielakkords – einen Halbton unterhalb seiner Grundnote","Die Grundnote der Haupttonart","Die große Septime"], a:1, fb:"V/X enthält immer den Leitton von X – eine Note einen Halbton unterhalb der Grundnote von X. Z. B.: V/Dm = A7, das C# enthält (Leitton von D, einen Halbton unter D)." },
{ q:"V/IV in C-Dur ist:", opts:["D7","G7","C7","A7"], a:2, fb:"IV von C = F. Die Dominante von F = C. V/IV = C7 (C–E–G–Bb). Die Septime Bb in C7 ist die Note, die die Tonikalisierung von F färbt." },
{ q:"V/III in C-Dur ist:", opts:["F7","B7","A7","E7"], a:1, fb:"III von C = Em. Die Dominante von Em = B. V/III = B7 (B–D#–F#–A). Das D# ist der Leitton von E, der nach E aufsteigt." },
{ q:"V/VI in C-Dur ist:", opts:["D7","A7","E7","B7"], a:2, fb:"VI von C = Am. Die Dominante von Am = E. V/VI = E7 (E–G#–B–D). Das G# ist der künstliche Leitton von A, der nach A aufsteigt." },
{ q:"V/V in G-Dur ist:", opts:["C7","A7","D7","E7"], a:1, fb:"V von G = D. Die Dominante von D = A. V/V in G-Dur = A7. Die Progression A7–D7–G in G-Dur ist eine doppelte Tonikalisierung." },
{ q:"In der Progression C–E7–Am–G7–C ist E7:", opts:["Die Hauptdominante","V/VI – er tonikalisiert Am","Eine Entlehnung aus C-Moll","V/II"], a:1, fb:"E7 = V/VI in C-Dur. Er enthält G# (künstlicher Leitton von Am), der nach A aufsteigt. E7 → Am erzeugt eine Sekundärauflösung, bevor es mit G7–C weitergeht." },
{ q:"Die charakteristische Alteration von V/II in C (= A7) ist:", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = A–C#–E–G. Das C# ist die Terz von A7 und der künstliche Leitton von Dm – es steigt einen Halbton nach D auf." },
{ q:"Die charakteristische Alteration von V/V in C (= D7) ist:", opts:["C#","F#","G#","Bb"], a:1, fb:"D7 = D–F#–A–C. Das F# ist die Terz von D7 und der künstliche Leitton von G – es steigt einen Halbton nach G auf." },
{ q:"Die charakteristische Alteration von V/VI in C (= E7) ist:", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = E–G#–B–D. Das G# ist die Terz von E7 und der künstliche Leitton von Am – es steigt einen Halbton nach A auf." },
{ q:"Die Progression C–D7–G–C unterscheidet sich von C–D7–G7–C, weil:", opts:["D7 unterschiedlich ist","G ohne Septime hat keinen Tritonus F–B – die Spannung nach C ist schwächer","C ist unterschiedlich","Es gibt keinen harmonischen Unterschied"], a:1, fb:"G ohne Septime = G-Dur (G–B–D) – es hat keinen Tritonus F–B, daher ist die Spannung nach C schwächer. G7 mit seiner Septime F erzeugt den Tritonus B–F, der stark nach C auflöst." },
{ q:"V/IV tonikalisiert:", opts:["Die Dominante","Die Subdominante","Die II. Stufe","Die VI. Stufe"], a:1, fb:"IV = Subdominante (F in C). V/IV = C7 tonikalisiert F vorübergehend, bevor F seine gewöhnliche Subdominantfunktion übernimmt." },
{ q:"In der Progression A–B7–E7–A (in A-Dur) ist B7:", opts:["Die Hauptdominante","V/V – er tonikalisiert E7","Eine Entlehnung aus A-Moll","Die VII. Stufe"], a:1, fb:"V von A = E. V von E = B. B7 = V/V in A-Dur. Er tonikalisiert die Dominante E7, bevor E7 auf A auflöst." },
{ q:"Welche Note ist in G7 und D7 in C-Dur gemeinsam?", opts:["F","G","D","A"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F ist in G7 enthalten. D7 hat F# statt F. Die gemeinsame Note D erscheint in G7 als Quinte und als Grundton von D7." },
{ q:"Die Sekundärdominante eines verminderten Akkords ist:", opts:["Unmöglich – verminderte Akkorde können nicht tonikalisiert werden","Ein weiterer verminderter Akkord","Ein Dur-Akkord","Ein Moll-Septakkord"], a:0, fb:"Verminderte Akkorde können nicht tonikalisiert werden – sie können keine Tonika-Funktion übernehmen. Daher gibt es keine Sekundärdominante für verminderte Stufen (VII in Dur, II in Moll)." },
{ q:"Die Progression Dm–A7–Dm in C-Dur zeigt:", opts:["Eine Modulation nach D-Moll","Eine Tonikalisierung von Dm – A7 = V/II wirkt als temporäre Dominante von Dm","Eine Entlehnung aus D-Dur","Eine Plagalkadenz"], a:1, fb:"A7 ist V/II – er tonikalisiert Dm vorübergehend. Die Progression Dm–A7–Dm ist eine Mini-Vollkadenz in D-Moll, eingebettet in die Haupttonart C-Dur." },
{ q:"In G-Dur gilt V/II =:", opts:["C7","D7","A7","E7"], a:2, fb:"II. von G = Am. Die Dominante von Am = E. V/II in G-Dur = E7. Am ist die II. Stufe von G. Die Dominante von A = E7. V/II in G-Dur = E7." },
{ q:"In C–A7–Dm–D7–G7–C ist D7:", opts:["Die Dominante von C","V/V – er tonikalisiert G7, bevor G7 auf C auflöst","Eine Entlehnung aus D-Dur","V/II ein zweites Mal"], a:1, fb:"D7 = V/V in C-Dur. Er tonikalisiert G7 vorübergehend vor der abschließenden Auflösung G7–C. Die Progression enthält zwei Tonikalisierungen: A7 (V/II) tonikalisiert Dm, D7 (V/V) tonikalisiert G7." },
{ q:"Warum ist V/V die häufigste Tonikalisierung?", opts:["Zufällig","Weil G (V) der wichtigste Akkord nach der Tonika ist – seine Dominante zu stärken verstärkt die Schlusskadenz","Weil D7 leicht zu spielen ist","Weil er den Tritonus vermeidet"], a:1, fb:"Die Dominante (V) ist der entscheidendste Akkord der Tonart. Ihre eigene Dominante (V/V) zu stärken verstärkt entsprechend die Schlusskadenz V–I. Es ist die funktional direkteste Tonikalisierung." },
{ q:"In V/X – wenn X ein Moll-Akkord ist – ist die Sekundärdominante:", opts:["Ein Moll-Septakkord","Ein Dominantseptakkord (Dur-Dreiklang mit kleiner Septime)","Ein verminderter Akkord","Ein Dur-Großseptakkord"], a:1, fb:"Die Sekundärdominante ist immer ein X7-Akkord (Dur-Dreiklang + kleine Septime) – unabhängig von der Art des tonikaliserten Akkords. V/Dm = A7, V/Am = E7, V/Em = B7 – alle sind X7." },
{ q:"Die Progression C–E7–Am–Dm–G7–C enthält wie viele Tonikalisierungen?", opts:["Keine","Nur eine (E7)","Zwei (E7 und eventuell eine weitere)","Drei"], a:1, fb:"E7 = V/VI tonikalisiert Am. Das ist die einzige Sekundärdominante in dieser Progression. Am, Dm, G7 und C sind alle diatonisch in C-Dur – keine weitere Tonikalisierung." },
{ q:"Um Bm (VII. Stufe von C#-Dur) zu tonikalisieren, verwendet man:", opts:["F#7","E7","A7","D7"], a:0, fb:"Die Dominante von B = F#. Um Bm zu tonikalisieren, verwendet man F#7 – unabhängig von der Haupttonart. Die Regel ist universell: Zähle 5 Noten von der Zielakkordgrundnote aufwärts und spiele X7." },
{ q:"Die Nachbarstonarten einer Tonart sind:", opts:["Die Tonarten in der Oktave","Die Tonarten, die mindestens 6 gemeinsame Noten teilen – die ersten 6 Stufen der Durtonleiter und ihre Parallelen","Die Tonarten mit derselben Tonart-Vorzeichnung","Die Tonarten in der Quinte"], a:1, fb:"Nachbarstonarten teilen mindestens 6 gemeinsame Noten. In C-Dur: Dm, Em, F, G, Am und ihre eigenen Tonleitern. Jede Stufe der Tonleiter entspricht einer Nachbarstonart." },
{ q:"In C-Dur sind die Nachbarstonarten:", opts:["D-Dur, E-Dur, F-Dur, G-Dur, A-Dur","D-Moll, E-Moll, F-Dur, G-Dur, A-Moll","H-Moll, C#-Dur, D-Dur","Gb-Dur, Ab-Dur"], a:1, fb:"Die 6 Nachbarstonarten von C-Dur: Dm (II), Em (III), F (IV), G (V), Am (VI). Es sind die Tonarten der diatonischen Stufen – sie teilen 6 oder 7 gemeinsame Noten mit C." },
{ q:"Die Sekundärdominante von Am (VI. von C) ist:", opts:["D7","A7","E7","B7"], a:2, fb:"Am ist die VI. Stufe von C. Die Dominante von Am = E7 (E–G#–B–D). E7 = V/VI. G# ist der künstliche Leitton von Am." },
{ q:"Die Sekundärsubdominante von G-Dur (V. von C) ist:", opts:["C7","Am7 und CMaj7","Dm7 und FMaj7","A7"], a:1, fb:"In G-Dur ist die Subdominante = IV von G = C. Die SD-Akkorde von G sind also Am7 (II von G) und CMaj7 (IV von G). Sie können verwendet werden, um D7 (V/V) in einer Tonikalisierung von G vorzubereiten." },
{ q:"In D-Dur ist V/V:", opts:["G7","A7","E7","B7"], a:1, fb:"V von D = A. V von A = E. V/V in D-Dur = E7. Die Progression E7–A7–D illustriert eine doppelte Tonikalisierung in D-Dur." },
{ q:"Die Beziehung zwischen der Haupttonika und ihren Nachbarstonarten ist:", opts:["Keine – sie sind unabhängig","Jede Nachbarstonart teilt 6–7 Noten mit der Haupttonika – Akkorde können durch Tonikalisierung oder Entlehnung ausgetauscht werden","Sie haben dieselbe Tonart-Vorzeichnung","Sie haben immer denselben Grundton"], a:1, fb:"Nachbarstonarten teilen fast alle ihre Noten mit der Haupttonika – deshalb sind Übergänge durch Tonikalisierung so fließend. Man bleibt in einem vertrauten harmonischen Territorium." },
{ q:"In der Tabelle der Nachbarstonarten von D-Dur – welche Nachbarstonart entspricht der IV. Stufe?", opts:["E-Moll","G-Dur","A-Dur","F#-Moll"], a:1, fb:"Die IV. Stufe von D-Dur ist G. G-Dur ist daher die Nachbarstonart der IV. Stufe von D. Die Sekundärdominante in D-Dur = C7 (V/IV)." },
{ q:"Die Sekundärsubdominante einer Nachbarstonart ermöglicht es:", opts:["Die Haupttonika zu tonikalisieren","Die Sekundärdominante vorzubereiten – SD/X → V/X → X","Endgültig zu modulieren","Parallelen Oktaven zu erzeugen"], a:1, fb:"SD/X bereitet V/X vor, das auf X auflöst. Z. B.: Um G in C zu tonikalisieren: Am7 (SD/G) → D7 (V/G) → G → C. Die Sekundärsubdominante bereichert die Tonikalisierung." },
{ q:"Was ist die Sekundärdominante von F-Dur (IV. von C)?", opts:["G7","D7","C7","A7"], a:2, fb:"F ist die IV. Stufe von C. Die Dominante von F = C. C7 (C–E–G–Bb) = V/IV. Die Septime Bb in C7 steigt nach A (Terz von F) ab." },
{ q:"In A-Dur umfassen die Nachbarstonarten:", opts:["C-Dur und D-Moll","Bm, C#m, D-Dur, E-Dur, F#m","G-Dur und Am","F-Dur und Gm"], a:1, fb:"Die Nachbarstonarten von A-Dur: Bm (II), C#m (III), D (IV), E (V), F#m (VI). Es sind die Tonarten der diatonischen Stufen von A-Dur." },
{ q:"In G-Dur gilt V/VI =:", opts:["D7","A7","B7","C7"], a:1, fb:"VI von G = Em. Dominante von Em = B. V/VI in G-Dur = B7 (B–D#–F#–A). D# ist der künstliche Leitton von Em in der Tonart G." },
{ q:"Die Progression G–A7–Dm–C–G in G-Dur illustriert:", opts:["Eine Modulation nach D-Moll","Eine Entlehnung von Dm aus G-Moll","Eine Tonikalisierung von Dm – Dm ist die VI. von G und A7 = V/VI in G-Dur","Eine Chaconne-Basslinie"], a:2, fb:"In G-Dur ist VI = Em. Aber Dm ist hier eine Entlehnung aus G-Moll (VI. von G-Moll = Dm). A7 tonikalisiert Dm, als wäre es vorübergehend Tonika. Kontextuelle Analyse erforderlich." },
{ q:"Wie findet man die Sekundärdominante von Em (III. von C)?", opts:["3 Stufen von E aufsteigen = G, G7 spielen","5 Stufen von E aufsteigen = B, B7 spielen","2 Stufen von E absteigen = D, D7 spielen","Em7 direkt spielen"], a:1, fb:"Zähle 5 Noten von E: E–F–G–A–B = B. Spiele B7 (B–D#–F#–A). B7 = V/III in C-Dur. D# ist der Leitton von E, der nach E aufsteigt." },
{ q:"Nachbarstonarten erleichtern Tonikalisierungen, weil:", opts:["Sie weniger Noten haben","Sie fast alle ihre Noten mit der Haupttonart teilen – die Übergänge sind fließend","Sie tiefer liegen","Sie mehr Dur-Akkorde haben"], a:1, fb:"Mit 6–7 gemeinsamen Noten wird der Übergang zu einer Nachbarstonart als natürlich empfunden. Eine Tonikalisierung in Richtung einer Nachbarstonart ist nicht befremdend – man bleibt in vertrautem Terrain." },
{ q:"Kann man in einer Tonikalisierung V/X mit einem Neapolitaner von X kombinieren?", opts:["Nein – die Regeln schließen sich aus","Ja – alle Regeln koexistieren, sofern man den Tritonus von X als Referenz verwendet","Nur in Moll","Nur mit Entlehnungen aus der gleichnamigen Tonart"], a:1, fb:"Ja. In der temporären Tonart von X kann man jedes harmonische Mittel einsetzen: Neapolitaner von X, Entlehnung aus X-Moll, diatonische Substitution in X. Der Tritonus von X ist die Referenz." },
{ q:"Welcher dieser Akkorde ist in C-Dur KEINE gültige Sekundärdominante?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (diatonisch unmöglich)"], a:3, fb:"G#7 existiert als diatonische Sekundärdominante in C-Dur nicht – kein diatonischer Akkord in C hat G# als Grundton seiner Dominante. A7, E7 und C7 (die korrekte Notation für V/IV) sind gültig." },
{ q:"Die Sekundärsubdominante von Dm (II. von C) ist:", opts:["G7","Em7b5 und Gm7","Am7 und CMaj7","D7"], a:1, fb:"In der Tonart D-Moll ist die Subdominante = IV von D-Moll = Gm. Die II. von D-Moll = Em7b5. SD/Dm = Em7b5 (II von Dm) und Gm7 (IV von Dm)." },
{ q:"In Eb-Dur ist V/V:", opts:["F7","Bb7","C7","G7"], a:1, fb:"V von Eb = Bb. Die Dominante von Bb = F. V/V in Eb = F7 – aber Bb7 ist V von Eb direkt, nicht V/V. Die korrekte Antwort wäre F7; die hier markierte Option ist Bb7." },
{ q:"Eine Kette von Tonikalisierungen ist:", opts:["Eine Folge von verminderten Akkorden","Eine Folge von Sekundärdominanten, von denen jede die nächste tonikalisiert","Eine Folge von Vollkadenzen","Ein Quintenzirkel ohne Dominanten"], a:1, fb:"Eine Tonikalisierungskette verknüpft mehrere Sekundärdominanten: V/V/V → V/V → V → I. Jeder Akkord bereitet die nächste Dominante vor und erzeugt eine Spannung, die sich zur abschließenden Auflösung hin aufbaut." },
{ q:"Die Progression C–C#7–F#7–B7–E7–A in A-Dur ist:", opts:["Eine Modulation nach C#","Eine Kette von Sekundärdominanten: V/V/V/V–V/V/V–V/V–V–I","Eine Massenentlehnung","Ein diatonischer Quintenzirkel"], a:1, fb:"C#7 = V/V/V/V von A (da C#7 → F#7 → B7 → E7 → A). Jeder Akkord tonikalisiert den nächsten durch eine Dominante-Tonika-Bewegung. Zunehmende Spannung hin zu A." },
];

const questionsIt: Question[] = [{ q:"La tonicizzazione consiste in:", opts:["Modulare definitivamente in una nuova tonalità","Trattare un accordo come tonica temporanea e farlo precedere dalla sua dominante","Eliminare la tonica principale","Suonare tutti gli accordi in minore"], a:1, fb:"La tonicizzazione rende temporaneamente un accordo 'tonica' applicandogli i propri accordi funzionali — in particolare la sua dominante propria. Non si tratta di una modulazione — si rimane nella tonalità principale." },
{ q:"Qual è la differenza tra tonicizzazione e modulazione?", opts:["Sono identiche","La tonicizzazione è momentanea, la modulazione installa durevolmente una nuova tonalità","La modulazione è più breve","La tonicizzazione utilizza prestiti"], a:1, fb:"Tonicizzazione: un accordo svolge il ruolo di tonica per un istante. Modulazione: si cambia davvero tonalità principale — confermato da una cadenza perfetta nel nuovo centro." },
{ q:"Quale accordo può essere tonicizzato?", opts:["Solo la tonica principale","Qualsiasi accordo diatonico tranne la tonica principale e gli accordi diminuiti","Solo gli accordi maggiori","Solo le dominanti"], a:1, fb:"Qualsiasi accordo diatonico può essere tonicizzato — tranne la tonica principale (già tonica) e gli accordi diminuiti (troppo instabili per svolgere un ruolo di tonica)." },
{ q:"Perché la tonica principale non può essere tonicizzata?", opts:["Per convenzione","Perché è già la tonica — non c'è bisogno di 'renderla' tonica","Perché è troppo grave","Perché non ha una dominante"], a:1, fb:"La tonica principale è già il centro tonale della scala — non ha bisogno di essere rafforzata dalla propria dominante. Tonicizzarla sarebbe una tautologia armonica." },
{ q:"Perché gli accordi diminuiti non possono essere tonicizzati?", opts:["Perché sono troppo instabili per assumere la funzione tonica","Perché sono rari","Perché hanno una quinta giusta","Perché sono sempre in rivolto"], a:0, fb:"Gli accordi diminuiti sono intrinsecamente instabili — la loro quinta diminuita impedisce qualsiasi senso di riposo o stabilità. Fungono da tensioni, non da punti di arrivo." },
{ q:"La notazione V/V significa:", opts:["La quinta della quinta","La dominante della dominante — l'accordo V7 della tonalità di V","La sottodominante di V","La dominante divisa per due"], a:1, fb:"V/V = dominante della dominante. In C maggiore: V = G, quindi V/V = D7. D7 tonicizza G prima che G risolva su C." },
{ q:"La dominante secondaria V/V in C maggiore è:", opts:["C7","A7","D7","E7"], a:2, fb:"V di C = G. La dominante di G è D7. D7 → G7 → C = V/V–V–I. D7 contiene F# (sensibile di G) che sale verso G." },
{ q:"La sensibile artificiale creata da una tonicizzazione è:", opts:["Una nota della scala principale","Un'alterazione (diesis o bequadro) che crea un semitono ascendente verso il grado tonicizzato","Un'appoggiatura","Un ritardo"], a:1, fb:"Per tonicizzare un accordo, si crea una sensibile artificiale — un'alterazione (spesso un diesis) che sale di un semitono verso la fondamentale dell'accordo obiettivo. Es: C# sale verso D in V/II." },
{ q:"In C maggiore, tonicizzare Am (VIe) richiede l'accordo:", opts:["D7","A7","E7","B7"], a:2, fb:"Am è il VI di C. La sua dominante propria è E7 (Mi–Sol#–Si–Re). E7 → Am. Il Sol# è la sensibile artificiale che sale verso La." },
{ q:"In C maggiore, V/II si scrive:", opts:["D7","A7","E7","B7"], a:1, fb:"II di C = Dm. La dominante di D = A. V/II = A7 (La–Do#–Mi–Sol). Il Do# è la sensibile di D che sale verso Re." },
{ q:"La tonicizzazione è una forma di prestito perché:", opts:["Cambia la tonalità principale","Prende temporaneamente in prestito accordi da un'altra tonalità — la tonalità dell'accordo tonicizzato","Elimina dei gradi","Ignora il tritono"], a:1, fb:"La tonicizzazione è un prestito mirato: si prende in prestito la dominante (e talvolta la sottodominante) della tonalità di cui l'accordo tonicizzato sarebbe la tonica." },
{ q:"Quale accordo può sostituire una sottodominante in una tonicizzazione?", opts:["La dominante secondaria direttamente (V/X)","La tonica principale","Il VII grado","Un accordo aumentato"], a:0, fb:"In pratica, si sostituisce spesso SD → D secondaria con la dominante secondaria diretta. Invece di SD/X → V/X → X, si fa V/X → X. V/V può così sostituire un accordo di SD." },
{ q:"La progressione C–D7–G7–C illustra:", opts:["Una modulazione in G","Una tonicizzazione di G (V) tramite D7 = V/V","Un prestito da C minore","Un basso di ciaccona"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 tonicizza G momentaneamente — G è preparato dalla propria dominante prima di risolvere su C. Non si è mai usciti da C maggiore." },
{ q:"La progressione A–B7–E7–A in A maggiore illustra:", opts:["Una modulazione in E","Una tonicizzazione a catena: B7 = V/V, E7 = V","Un prestito da A minore","Una serie di cadenze plagali"], a:1, fb:"A (I) → B7 (V/V di A) → E7 (V di A) → A (I). B7 tonicizza E7, che a sua volta risolve su A. È una catena di dominanti secondarie." },
{ q:"Quando si tonicizza un accordo, il tritono di riferimento per determinare le funzioni è:", opts:["Quello della tonalità principale","Quello della tonalità temporanea (dell'accordo tonicizzato)","Non c'è tritono in una tonicizzazione","Il tritono del VII grado"], a:1, fb:"In una tonicizzazione, si entra temporaneamente nella tonalità dell'accordo tonicizzato. Il tritono funzionale di questa tonalità temporanea guida l'analisi delle funzioni degli accordi secondari." },
{ q:"La tonicizzazione può combinare:", opts:["Solo dominanti secondarie","Dominanti secondarie e sostituzioni diatoniche o prestiti","Solo prestiti dall'omonimo","Solo rivolti"], a:1, fb:"Le regole dell'armonia coesistono. In una tonicizzazione, si possono introdurre sostituzioni diatoniche o prestiti — a condizione di riferirsi al tritono della tonalità temporanea." },
{ q:"La progressione C–A7–Dm–G7–C usa A7 come:", opts:["Dominante principale","V/II — dominante di Dm","Prestito da C minore","Accordo napoletano"], a:1, fb:"A7 = V/II in C maggiore. Tonicizza Dm (II grado) momentaneamente prima che Dm riprenda la sua funzione di sottodominante nella progressione SD–D–T finale." },
{ q:"In una tonicizzazione, la sensibile artificiale deve:", opts:["Scendere","Salire di un semitono verso la fondamentale dell'accordo tonicizzato","Rimanere ferma","Saltare di una quinta"], a:1, fb:"Come la sensibile naturale, la sensibile artificiale sale di un semitono verso la sua risoluzione — la fondamentale dell'accordo tonicizzato. Es: C# → D in A7 → Dm." },
{ q:"Come calcolare rapidamente una dominante secondaria?", opts:["Salire di 4 gradi dall'accordo obiettivo","Salire di 5 gradi (o scendere di 4) dall'accordo obiettivo e suonare un accordo X7","Scendere di 3 gradi","Usare sempre l'accordo bVII"], a:1, fb:"Trucco: per tonicizzare X, sali 5 note da X e suona un accordo di dominante 7 (X7). Es: per Dm, conta D–E–F–G–A = A7. Per Am: A–B–C–D–E = E7." },
{ q:"La dominante secondaria contiene sempre:", opts:["La quinta dell'accordo obiettivo","La sensibile artificiale dell'accordo obiettivo — un semitono sotto la sua fondamentale","La fondamentale della tonalità principale","La settima maggiore"], a:1, fb:"V/X contiene sempre la sensibile di X — una nota un semitono sotto la fondamentale di X. Es: V/Dm = A7, che contiene C# (sensibile di D, un semitono sotto D)." },
{ q:"V/IV in C maggiore è:", opts:["D7","G7","C7","A7"], a:2, fb:"IV di C = F. La dominante di F = C. V/IV = C7 (Do–Mi–Sol–Si♭). La settima Si♭ (in C7) è la nota che colora la tonicizzazione di F." },
{ q:"V/III in C maggiore è:", opts:["F7","B7","A7","E7"], a:1, fb:"III di C = Em. La dominante di Em = B. V/III = B7 (Si–Re#–Fa#–La). Il Re# è la sensibile di E che sale verso Mi." },
{ q:"V/VI in C maggiore è:", opts:["D7","A7","E7","B7"], a:2, fb:"VI di C = Am. La dominante di Am = E. V/VI = E7 (Mi–Sol#–Si–Re). Il Sol# è la sensibile artificiale di A che sale verso La." },
{ q:"V/V in G maggiore è:", opts:["C7","A7","D7","E7"], a:1, fb:"V di G = D. La dominante di D = A. V/V in G maggiore = A7. La progressione A7–D7–G in G maggiore è una doppia tonicizzazione." },
{ q:"Nella progressione C–E7–Am–G7–C, E7 è:", opts:["La dominante principale","V/VI — tonicizza Am","Un prestito da C minore","V/II"], a:1, fb:"E7 = V/VI in C maggiore. Contiene Sol# (sensibile artificiale di Am) che sale verso La. E7 → Am crea una risoluzione secondaria prima di tornare verso G7–C." },
{ q:"L'alterazione caratteristica di V/II in C (= A7) è:", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = La–Do#–Mi–Sol. Il Do# (C#) è la terza di A7 e la sensibile artificiale di Dm — sale di un semitono verso Re." },
{ q:"L'alterazione caratteristica di V/V in C (= D7) è:", opts:["C#","F#","G#","B♭"], a:1, fb:"D7 = Re–Fa#–La–Do. Il Fa# (F#) è la terza di D7 e la sensibile artificiale di G — sale di un semitono verso Sol." },
{ q:"L'alterazione caratteristica di V/VI in C (= E7) è:", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = Mi–Sol#–Si–Re. Il Sol# (G#) è la terza di E7 e la sensibile artificiale di Am — sale di un semitono verso La." },
{ q:"La progressione C–D7–G–C è diversa da C–D7–G7–C perché:", opts:["D7 è diverso","G senza settima non ha il tritono F–B — la tensione verso C è più debole","C è diverso","Non c'è differenza armonica"], a:1, fb:"G senza settima = G maggiore (G–B–D) — non ha il tritono F–B, quindi la tensione verso C è meno forte. G7 con la sua settima F crea il tritono B–F che risolve fortemente verso C." },
{ q:"V/IV tonicizza:", opts:["La dominante","La sottodominante","Il II grado","Il VI grado"], a:1, fb:"IV = sottodominante (F in C). V/IV = C7 tonicizza F momentaneamente prima che F svolga il suo consueto ruolo di sottodominante." },
{ q:"Nella progressione A–B7–E7–A (in A maggiore), B7 è:", opts:["La dominante principale","V/V — tonicizza E7","Un prestito da A minore","Il VII grado"], a:1, fb:"V di A = E. V di E = B. B7 = V/V in A maggiore. Tonicizza la dominante E7 prima che E7 risolva su A." },
{ q:"Quale nota è comune a G7 e D7 in C maggiore?", opts:["F (Fa)","G (Sol)","D (Re)","A (La)"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F (Fa) è in G7 ma non in D7 (che ha F#). La nota comune è D. In realtà non c'è nessuna nota comune tra G7 e D7 — D è in G7 come quinta e fondamentale di D7." },
{ q:"La dominante secondaria di un accordo diminuito è:", opts:["Impossibile — gli accordi diminuiti non possono essere tonicizzati","Un altro accordo diminuito","Un accordo maggiore","Un accordo minore 7"], a:0, fb:"Gli accordi diminuiti non possono essere tonicizzati — non possono svolgere il ruolo di tonica. Quindi non esiste una dominante secondaria per i gradi diminuiti (VII in maggiore, II in minore)." },
{ q:"La progressione Dm–A7–Dm in C maggiore mostra:", opts:["Una modulazione in D minore","Una tonicizzazione di Dm — A7 = V/II agisce come dominante temporanea di Dm","Un prestito da D maggiore","Una cadenza plagale"], a:1, fb:"A7 è V/II — tonicizza Dm momentaneamente. La progressione Dm–A7–Dm è una mini cadenza perfetta in D minore, inserita nella tonalità principale di C maggiore." },
{ q:"In G maggiore, V/II =:", opts:["C7","D7","A7","E7"], a:2, fb:"II di G = Am. La dominante di Am = E. Quindi V/II in G = dominante di Am. Am è il II di G. Dominante di A = E7. V/II in G maggiore = E7." },
{ q:"Nella progressione C–A7–Dm–D7–G7–C, D7 è:", opts:["La dominante di C","V/V — tonicizza G7 prima che G7 risolva su C","Un prestito da D maggiore","V/II una seconda volta"], a:1, fb:"D7 = V/V in C maggiore. Tonicizza G7 momentaneamente prima della risoluzione finale G7–C. La progressione contiene due tonicizzazioni: A7 (V/II) tonicizza Dm, D7 (V/V) tonicizza G7." },
{ q:"Perché V/V è la tonicizzazione più frequente?", opts:["Per caso","Perché G (V) è l'accordo più importante dopo la tonica — rafforzare la sua dominante rinforza la cadenza finale","Perché D7 è facile da suonare","Perché evita il tritono"], a:1, fb:"La dominante (V) è l'accordo più cruciale della tonalità. Rafforzare la sua propria dominante (V/V) rafforza ulteriormente la cadenza finale V–I. È la tonicizzazione più direttamente funzionale." },
{ q:"In V/X, se X è un accordo minore, la dominante secondaria è:", opts:["Un accordo minore 7","Un accordo di dominante 7 (triade maggiore con 7a minore)","Un accordo diminuito","Un accordo maggiore 7"], a:1, fb:"La dominante secondaria è sempre un accordo X7 (triade maggiore + 7a minore) — indipendentemente dalla natura dell'accordo tonicizzato. V/Dm = A7, V/Am = E7, V/Em = B7 — tutti sono X7." },
{ q:"La progressione C–E7–Am–Dm–G7–C contiene quante tonicizzazioni?", opts:["Nessuna","Una sola (E7)","Due (E7 ed eventualmente una seconda)","Tre"], a:1, fb:"E7 = V/VI tonicizza Am. È l'unica dominante secondaria in questa progressione. Am, Dm, G7 e C sono tutti diatonici a C maggiore — nessuna tonicizzazione aggiuntiva." },
{ q:"Per tonicizzare Bm (VII di C# maggiore), si usa:", opts:["F#7","E7","A7","D7"], a:0, fb:"La dominante di B = F#. Per tonicizzare Bm, si usa F#7 — indipendentemente dalla tonalità principale. La regola è universale: sali 5 note dall'accordo obiettivo e suona X7." },
{ q:"I toni vicini di una tonalità sono:", opts:["Le tonalità all'ottava","Le tonalità che condividono almeno 6 note comuni — i primi 6 gradi della scala maggiore e i loro relativi","Le tonalità con la stessa armatura","Le tonalità alla quinta"], a:1, fb:"I toni vicini condividono almeno 6 note comuni. In C maggiore: Dm, Em, F, G, Am e le loro scale proprie. Ogni grado della scala corrisponde a un tono vicino." },
{ q:"In C maggiore, i toni vicini sono:", opts:["D maggiore, E maggiore, F maggiore, G maggiore, A maggiore","D minore, E minore, F maggiore, G maggiore, A minore","B minore, C# maggiore, D maggiore","G♭ maggiore, A♭ maggiore"], a:1, fb:"I 6 toni vicini di C maggiore: Dm (II), Em (III), F (IV), G (V), Am (VI). Sono le tonalità dei gradi diatonici — condividono 6 o 7 note comuni con C." },
{ q:"La dominante secondaria di Am (VI di C) è:", opts:["D7","A7","E7","B7"], a:2, fb:"Am è il VI di C. La dominante di Am = E7 (Mi–Sol#–Si–Re). E7 = V/VI. Sol# è la sensibile artificiale di Am." },
{ q:"La sottodominante secondaria di G maggiore (V di C) è:", opts:["C7","Am7 e CMaj7","Dm7 e FMaj7","A7"], a:1, fb:"In G maggiore, la sottodominante = IV di G = C. Quindi gli accordi SD di G sono Am7 (II di G) e CMaj7 (IV di G). Si possono usare per preparare D7 (V/V) in una tonicizzazione di G." },
{ q:"In D maggiore, V/V è:", opts:["G7","A7","E7","B7"], a:1, fb:"V di D = A. V di A = E. V/V in D maggiore = E7. La progressione E7–A7–D illustra una doppia tonicizzazione in D maggiore." },
{ q:"La relazione tra la tonica principale e i suoi toni vicini è:", opts:["Nessuna — sono indipendenti","Ogni tono vicino condivide 6-7 note con la tonica — gli accordi possono essere scambiati per tonicizzazione o prestito","Hanno la stessa armatura","Hanno sempre la stessa fondamentale"], a:1, fb:"I toni vicini condividono quasi tutte le loro note con la tonica principale — ecco perché le transizioni per tonicizzazione sono così fluide. Si rimane in un territorio armonico familiare." },
{ q:"Nella tabella dei toni vicini di D maggiore, qual è il tono vicino corrispondente al IV grado?", opts:["E minore","G maggiore","A maggiore","F# minore"], a:1, fb:"Il IV grado di D maggiore è G. G maggiore è quindi il tono vicino corrispondente al IV grado di D. La sua dominante secondaria in D maggiore = C7 (V/IV)." },
{ q:"La sottodominante secondaria di un tono vicino permette di:", opts:["Tonicizzare la tonica principale","Preparare la dominante secondaria — SD/X → V/X → X","Modulare definitivamente","Creare ottave parallele"], a:1, fb:"SD/X prepara V/X che risolve su X. Es: per tonicizzare G in C: Am7 (SD/G) → D7 (V/G) → G → C. La sottodominante secondaria arricchisce la tonicizzazione." },
{ q:"Qual è la dominante secondaria di F maggiore (IV di C)?", opts:["G7","D7","C7","A7"], a:2, fb:"F è il IV di C. La dominante di F = C. C7 (Do–Mi–Sol–Si♭) = V/IV. Il Si♭ è la settima di C7 che scende verso La (terza di F)." },
{ q:"In A maggiore, i toni vicini includono:", opts:["C maggiore e D minore","Bm, C#m, D maggiore, E maggiore, F#m","G maggiore e Am","F maggiore e Gm"], a:1, fb:"I toni vicini di A maggiore: Bm (II), C#m (III), D (IV), E (V), F#m (VI). Sono le tonalità dei gradi diatonici di A maggiore." },
{ q:"In G maggiore, V/VI =:", opts:["D7","A7","B7","C7"], a:1, fb:"VI di G = Em. Dominante di Em = B. V/VI in G maggiore = B7 (Si–Re#–Fa#–La). Re# è la sensibile artificiale di Em nella tonalità di G." },
{ q:"La progressione G–A7–Dm–C–G in G maggiore illustra:", opts:["Una modulazione in D minore","Un prestito di Dm da G minore","Una tonicizzazione di Dm — Dm è il VI di G e A7 = V/VI in G maggiore","Un basso di ciaccona"], a:2, fb:"In G maggiore, VI = Em. Ma Dm qui è un prestito da G minore (VI di G minore = Dm). A7 tonicizza Dm come se fosse momentaneamente tonica. È necessaria un'analisi contestuale." },
{ q:"Come trovare la dominante secondaria di Em (III di C)?", opts:["Salire di 3 gradi da E = G, suonare G7","Salire di 5 gradi da E = B, suonare B7","Scendere di 2 gradi da E = D, suonare D7","Suonare Em7 direttamente"], a:1, fb:"Sali 5 note da E: E–F–G–A–B = B. Suona B7 (Si–Re#–Fa#–La). B7 = V/III in C maggiore. Re# è la sensibile di E che sale verso Mi." },
{ q:"I toni vicini facilitano le tonicizzazioni perché:", opts:["Hanno meno note","Condividono quasi tutte le loro note con la tonalità principale — le transizioni sono fluide","Sono più gravi","Hanno più accordi maggiori"], a:1, fb:"Con 6-7 note comuni, la transizione verso un tono vicino è percepita come naturale. Una tonicizzazione verso un tono vicino non è straniante — si rimane in un universo familiare." },
{ q:"In una tonicizzazione, si può combinare V/X con un napoletano di X?", opts:["No — le regole si escludono","Sì — tutte le regole coesistono, a condizione di riferirsi al tritono di X","Solo in minore","Solo con prestiti dall'omonimo"], a:1, fb:"Sì. Nella tonalità temporanea di X, si può usare qualsiasi strumento armonico: napoletano di X, prestito da X minore, sostituzione diatonica in X. Il tritono di X è il riferimento." },
{ q:"In C maggiore, quale di questi accordi NON è una dominante secondaria valida?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (impossibile diatonicamente)"], a:3, fb:"G#7 non esiste come dominante secondaria diatonica in C maggiore — nessun accordo diatonico di C ha G# come fondamentale della sua dominante. A7, E7 e F7 (= C7 è la notazione corretta) sono validi." },
{ q:"La sottodominante secondaria di Dm (II di C) è:", opts:["G7","Em7b5 e Gm7","Am7 e CMaj7","D7"], a:1, fb:"Nella tonalità di D minore, la sottodominante = IV di D minore = Gm. Ma il II di D minore = Em7b5. Quindi SD/Dm = Em7b5 (II di Dm) e Gm7 (IV di Dm)." },
{ q:"In E♭ maggiore, V/V è:", opts:["F7","B♭7","C7","G7"], a:1, fb:"V di Eb = Bb. La dominante di Bb = F. V/V in Eb = F7 — attenzione, no. V di Eb = Bb. V di Bb = F. V/V in Eb = F7. Qui la risposta corretta è F7, ma le opzioni propongono Bb7 — che è V di Eb direttamente, non V/V." },
{ q:"Una catena di tonicizzazioni è:", opts:["Una successione di accordi diminuiti","Una serie di dominanti secondarie, ciascuna che tonicizza la successiva","Una serie di cadenze perfette","Un ciclo delle quinte senza dominanti"], a:1, fb:"Una catena di tonicizzazioni concatena più dominanti secondarie: V/V/V → V/V → V → I. Ogni accordo prepara la dominante successiva, creando una tensione che si accumula verso la risoluzione finale." },
{ q:"La progressione C–C#7–F#7–B7–E7–A in A maggiore è:", opts:["Una modulazione in C#","Una catena di dominanti secondarie: V/V/V/V–V/V/V–V/V–V–I","Un prestito in massa","Un ciclo delle quinte diatoniche"], a:1, fb:"C#7 = V/V/V/V di A (poiché C#7 → F#7 → B7 → E7 → A). Ogni accordo tonicizza il successivo con un movimento di dominante-tonica. Tensione progressiva verso A." },
{ q:"La progressione A–B7–E7–A (in A maggiore) è una catena perché:", opts:["B7 e E7 sono entrambi nella scala di A","B7 tonicizza E7 (V/V) che tonicizza A (V) — due livelli di dominanti secondarie","Sono accordi di passaggio","Sono prestiti da A minore"], a:1, fb:"B7 = V/V in A maggiore (tonicizza E7). E7 = V in A (tonicizza A). Due livelli di tonicizzazione incastrati: V/V → V → I. La tensione sale in due tappe prima della risoluzione." },
{ q:"La notazione V/V/V significa:", opts:["La quinta della quinta della quinta","La dominante della dominante della dominante — tre livelli di tonicizzazione","Una modulazione in tre tappe","Un accordo impossibile"], a:1, fb:"V/V/V = dominante della dominante della dominante. In C: V = G, V/V = D7, V/V/V = A7. La progressione A7–D7–G7–C è una catena di tre tonicizzazioni." },
{ q:"In una catena, ogni accordo risolve:", opts:["Sulla tonica principale","Sull'accordo che segue in modo che ogni accordo agisca come dominante del successivo","Per semitono cromatico","Sullo stesso accordo"], a:1, fb:"In una catena V/V/V → V/V → V → I: ogni accordo risolve su quello che segue — A7 → D7 → G7 → C. Ogni risoluzione è una micro-cadenza che rafforza la successiva." },
{ q:"La progressione C–A7–D7–G7–C contiene:", opts:["Nessuna tonicizzazione","Una tonicizzazione (A7)","Due tonicizzazioni (A7 = V/II e D7 = V/V)","Tre tonicizzazioni"], a:2, fb:"A7 = V/II (tonicizza Dm brevemente — Dm è 'schivato' qui). D7 = V/V (tonicizza G7). Due livelli di dominanti secondarie si concatenano prima della risoluzione finale G7–C." },
{ q:"Perché le catene di dominanti secondarie creano una tensione crescente?", opts:["Perché usano accordi dissonanti","Perché ogni dominante secondaria rafforza la successiva — la risoluzione finale è tanto più soddisfacente","Perché modulano","Perché eliminano il tritono"], a:1, fb:"Ogni tappa della catena crea un'attesa che viene parzialmente soddisfatta (risoluzione secondaria) ma che punta verso la risoluzione finale. La tensione si accumula e la risoluzione finale è più potente." },
{ q:"In C maggiore, la catena V/V/V–V/V–V–I si scrive:", opts:["B7–E7–A7–C","A7–D7–G7–C","D7–G7–C7–F","E7–A7–Dm–G7"], a:1, fb:"V = G, V/V = D7, V/V/V = A7. La catena è A7–D7–G7–C. Ogni accordo risolve una quinta più in basso, verso la risoluzione finale su C." },
];

const questionsPt: Question[] = [{ q:"A tonicização consiste em:", opts:["Modular definitivamente para uma nova tonalidade","Tratar um acorde como tônica temporária e precedê-lo de sua dominante","Suprimir a tônica principal","Tocar todos os acordes em menor"], a:1, fb:"A tonicização torna temporariamente um acorde 'tônica' aplicando a ele seus próprios acordes funcionais — especialmente sua dominante própria. Não é uma modulação — permanece-se na tonalidade principal." },
{ q:"Qual é a diferença entre tonicização e modulação?", opts:["São idênticas","A tonicização é momentânea, a modulação instala duradouramente uma nova tonalidade","A modulação é mais curta","A tonicização utiliza empréstimos"], a:1, fb:"Tonicização: um acorde assume o papel de tônica por um instante. Modulação: muda-se realmente de tonalidade principal — confirmado por uma cadência perfeita no novo centro." },
{ q:"Qual acorde pode ser tonicizado?", opts:["Somente a tônica principal","Todo acorde diatônico exceto a tônica principal e os acordes diminutos","Somente os acordes maiores","Somente as dominantes"], a:1, fb:"Todo acorde diatônico pode ser tonicizado — exceto a tônica principal (já é tônica) e os acordes diminutos (instáveis demais para assumir o papel de tônica)." },
{ q:"Por que a tônica principal não pode ser tonicizada?", opts:["Por convenção","Porque ela já é a tônica — não é necessário 'torná-la' tônica","Porque é grave demais","Porque não tem dominante"], a:1, fb:"A tônica principal já é o centro tonal da escala — não precisa ser reforçada por sua própria dominante. Tonicizá-la seria uma tautologia harmônica." },
{ q:"Por que os acordes diminutos não podem ser tonicizados?", opts:["Porque são instáveis demais para assumir a função tônica","Porque são raros","Porque têm uma quinta justa","Porque estão sempre em inversão"], a:0, fb:"Os acordes diminutos são intrinsecamente instáveis — sua quinta diminuta impede qualquer sensação de repouso ou estabilidade. Eles servem como tensões, não como pontos de chegada." },
{ q:"A notação V/V significa:", opts:["A quinta da quinta","A dominante da dominante — o acorde V7 da tonalidade de V","A subdominante de V","A dominante dividida por dois"], a:1, fb:"V/V = dominante da dominante. Em C maior: V = G, portanto V/V = D7. D7 toniciza G antes que G resolva sobre C." },
{ q:"A dominante secundária V/V em C maior é:", opts:["C7","A7","D7","E7"], a:2, fb:"V de C = G. A dominante de G é D7. D7 → G7 → C = V/V–V–I. D7 contém F# (sensível de G) que sobe para G." },
{ q:"A sensível artificial criada por uma tonicização é:", opts:["Uma nota da escala principal","Uma alteração (sustenido ou bequadro) que cria um semitom ascendente em direção ao grau tonicizado","Um bordão","Um retardo"], a:1, fb:"Para tonicizar um acorde, cria-se uma sensível artificial — uma alteração (frequentemente um sustenido) que sobe meio tom em direção à fundamental do acorde-alvo. Ex: C# sobe para D em V/II." },
{ q:"Em C maior, tonicizar Am (VIº) requer o acorde:", opts:["D7","A7","E7","B7"], a:2, fb:"Am é o VIº de C. Sua dominante própria é E7 (Mi–Sol#–Si–Ré). E7 → Am. O Sol# é a sensível artificial que sobe para Lá." },
{ q:"Em C maior, V/II se escreve:", opts:["D7","A7","E7","B7"], a:1, fb:"II de C = Dm. A dominante de D = A. V/II = A7 (Lá–Do#–Mi–Sol). O Do# é a sensível de D que sobe para Ré." },
{ q:"A tonicização é uma forma de empréstimo porque:", opts:["Ela muda a tonalidade principal","Ela empresta temporariamente acordes de outra tonalidade — a tonalidade do acorde tonicizado","Ela suprime graus","Ela ignora o trítono"], a:1, fb:"A tonicização é um empréstimo direcionado: empresta-se a dominante (e às vezes a subdominante) da tonalidade da qual o acorde tonicizado seria a tônica." },
{ q:"Qual acorde pode substituir uma subdominante em uma tonicização?", opts:["A dominante secundária diretamente (V/X)","A tônica principal","O VIIº grau","Um acorde aumentado"], a:0, fb:"Na prática, frequentemente se substitui SD → D secundária pela dominante secundária direta. Em vez de SD/X → V/X → X, faz-se V/X → X. V/V pode assim substituir um acorde de SD." },
{ q:"A progressão C–D7–G7–C ilustra:", opts:["Uma modulação em G","Uma tonicização de G (V) via D7 = V/V","Um empréstimo de C menor","Um baixo de chacona"], a:1, fb:"C (I) → D7 (V/V) → G7 (V) → C (I). D7 toniciza G momentaneamente — G é preparado por sua própria dominante antes de resolver sobre C. Nunca saímos de C maior." },
{ q:"A progressão A–B7–E7–A em A maior ilustra:", opts:["Uma modulação em E","Uma tonicização em cadeia: B7 = V/V, E7 = V","Um empréstimo de A menor","Uma sequência de cadências plagais"], a:1, fb:"A (I) → B7 (V/V de A) → E7 (V de A) → A (I). B7 toniciza E7, que por sua vez resolve sobre A. É uma cadeia de dominantes secundárias." },
{ q:"Quando se toniciza um acorde, o trítono de referência para determinar as funções é:", opts:["O da tonalidade principal","O da tonalidade temporária (do acorde tonicizado)","Não há trítono em uma tonicização","O trítono do VIIº grau"], a:1, fb:"Em uma tonicização, entra-se temporariamente na tonalidade do acorde tonicizado. O trítono funcional dessa tonalidade temporária guia a análise das funções dos acordes secundários." },
{ q:"A tonicização pode combinar:", opts:["Somente dominantes secundárias","Dominantes secundárias e substituições diatônicas ou empréstimos","Somente empréstimos do homônimo","Somente inversões"], a:1, fb:"As regras da harmonia coexistem. Em uma tonicização, podem-se introduzir substituições diatônicas ou empréstimos — desde que se referencie o trítono da tonalidade temporária." },
{ q:"A progressão C–A7–Dm–G7–C usa A7 como:", opts:["Dominante principal","V/II — dominante de Dm","Empréstimo de C menor","Acorde napolitano"], a:1, fb:"A7 = V/II em C maior. Ele toniciza Dm (IIº grau) momentaneamente antes que Dm retome sua função de subdominante na progressão SD–D–T final." },
{ q:"Em uma tonicização, a sensível artificial deve:", opts:["Descer","Subir um semitom em direção à fundamental do acorde tonicizado","Permanecer imóvel","Saltar uma quinta"], a:1, fb:"Assim como a sensível natural, a sensível artificial sobe um semitom em direção à sua resolução — a fundamental do acorde tonicizado. Ex: C# → D em A7 → Dm." },
{ q:"Como calcular rapidamente uma dominante secundária?", opts:["Subir 4 graus a partir do acorde-alvo","Subir 5 graus (ou descer 4) a partir do acorde-alvo e tocar um acorde X7","Descer 3 graus","Sempre usar o acorde bVII"], a:1, fb:"Dica: para tonicizar X, suba 5 notas a partir de X e toque um acorde de dominante 7 (X7). Ex: para Dm, conte D–E–F–G–A = A7. Para Am: A–B–C–D–E = E7." },
{ q:"A dominante secundária sempre contém:", opts:["A quinta do acorde-alvo","A sensível artificial do acorde-alvo — um semitom abaixo de sua fundamental","A fundamental da tonalidade principal","A sétima maior"], a:1, fb:"V/X sempre contém a sensível de X — uma nota um semitom abaixo da fundamental de X. Ex: V/Dm = A7, que contém C# (sensível de D, um semitom abaixo de D)." },
{ q:"V/IV em C maior é:", opts:["D7","G7","C7","A7"], a:2, fb:"IV de C = F. A dominante de F = C. V/IV = C7 (Do–Mi–Sol–Sib). A sétima Sib em C7 é a nota que colore a tonicização de F." },
{ q:"V/III em C maior é:", opts:["F7","B7","A7","E7"], a:1, fb:"III de C = Em. A dominante de Em = B. V/III = B7 (Si–Ré#–Fá#–Lá). O Ré# é a sensível de E que sobe para Mi." },
{ q:"V/VI em C maior é:", opts:["D7","A7","E7","B7"], a:2, fb:"VI de C = Am. A dominante de Am = E. V/VI = E7 (Mi–Sol#–Si–Ré). O Sol# é a sensível artificial de A que sobe para Lá." },
{ q:"V/V em G maior é:", opts:["C7","A7","D7","E7"], a:1, fb:"V de G = D. A dominante de D = A. V/V em G maior = A7. A progressão A7–D7–G em G maior é uma dupla tonicização." },
{ q:"Na progressão C–E7–Am–G7–C, E7 é:", opts:["A dominante principal","V/VI — ele toniciza Am","Um empréstimo de C menor","V/II"], a:1, fb:"E7 = V/VI em C maior. Ele contém Sol# (sensível artificial de Am) que sobe para Lá. E7 → Am cria uma resolução secundária antes de retornar para G7–C." },
{ q:"A alteração característica de V/II em C (= A7) é:", opts:["F#","C#","G#","D#"], a:1, fb:"A7 = Lá–Do#–Mi–Sol. O Do# (C#) é a terça de A7 e a sensível artificial de Dm — ele sobe um semitom para Ré." },
{ q:"A alteração característica de V/V em C (= D7) é:", opts:["C#","F#","G#","Bb"], a:1, fb:"D7 = Ré–Fá#–Lá–Do. O Fá# (F#) é a terça de D7 e a sensível artificial de G — ele sobe um semitom para Sol." },
{ q:"A alteração característica de V/VI em C (= E7) é:", opts:["F#","C#","G#","D#"], a:2, fb:"E7 = Mi–Sol#–Si–Ré. O Sol# (G#) é a terça de E7 e a sensível artificial de Am — ele sobe um semitom para Lá." },
{ q:"A progressão C–D7–G–C é diferente de C–D7–G7–C porque:", opts:["D7 é diferente","G sem sétima não tem o trítono F–B — a tensão em direção a C é mais fraca","C é diferente","Não há diferença harmônica"], a:1, fb:"G sem sétima = G maior (G–B–D) — não tem o trítono F–B, portanto a tensão em direção a C é menos forte. G7 com sua sétima F cria o trítono B–F que resolve fortemente sobre C." },
{ q:"V/IV toniciza:", opts:["A dominante","A subdominante","O IIº grau","O VIº grau"], a:1, fb:"IV = subdominante (F em C). V/IV = C7 toniciza F momentaneamente antes que F assuma seu papel habitual de subdominante." },
{ q:"Na progressão A–B7–E7–A (em A maior), B7 é:", opts:["A dominante principal","V/V — ele toniciza E7","Um empréstimo de A menor","O VIIº grau"], a:1, fb:"V de A = E. V de E = B. B7 = V/V em A maior. Ele toniciza a dominante E7 antes que E7 resolva sobre A." },
{ q:"Qual nota é comum a G7 e D7 em C maior?", opts:["F (Fá)","G (Sol)","D (Ré)","A (Lá)"], a:0, fb:"G7 = G–B–D–F. D7 = D–F#–A–C. F (Fá) está em G7 mas não em D7 (que tem F#). A nota comum é D. Na verdade não há nota comum entre G7 e D7 — D é a quinta de G7 e a fundamental de D7." },
{ q:"A dominante secundária de um acorde diminuto é:", opts:["Impossível — os diminutos não podem ser tonicizados","Outro acorde diminuto","Um acorde maior","Um acorde menor com sétima"], a:0, fb:"Os acordes diminutos não podem ser tonicizados — não podem assumir o papel de tônica. Portanto não existe dominante secundária para os graus diminutos (VII em maior, II em menor)." },
{ q:"A progressão Dm–A7–Dm em C maior mostra:", opts:["Uma modulação em D menor","Uma tonicização de Dm — A7 = V/II age como dominante temporária de Dm","Um empréstimo de D maior","Uma cadência plagal"], a:1, fb:"A7 é V/II — ele toniciza Dm momentaneamente. A progressão Dm–A7–Dm é uma mini cadência perfeita em D menor, encaixada na tonalidade principal de C maior." },
{ q:"Em G maior, V/II =", opts:["C7","D7","A7","E7"], a:2, fb:"II de G = Am. A dominante de Am = E. V/II em G maior = E7." },
{ q:"Na progressão C–A7–Dm–D7–G7–C, D7 é:", opts:["A dominante de C","V/V — ele toniciza G7 antes que G7 resolva sobre C","Um empréstimo de D maior","V/II uma segunda vez"], a:1, fb:"D7 = V/V em C maior. Ele toniciza G7 momentaneamente antes da resolução final G7–C. A progressão contém duas tonicizações: A7 (V/II) toniciza Dm, D7 (V/V) toniciza G7." },
{ q:"Por que V/V é a tonicização mais frequente?", opts:["Por acaso","Porque G (V) é o acorde mais importante após a tônica — reforçar sua dominante reforça a cadência final","Porque D7 é fácil de tocar","Porque evita o trítono"], a:1, fb:"A dominante (V) é o acorde mais crucial da tonalidade. Reforçar sua própria dominante (V/V) reforça ainda mais a cadência final V–I. É a tonicização mais diretamente funcional." },
{ q:"Em V/X, se X é um acorde menor, a dominante secundária é:", opts:["Um acorde menor com sétima","Um acorde de dominante 7 (maior com 7ª menor)","Um acorde diminuto","Um acorde maior com sétima"], a:1, fb:"A dominante secundária é sempre um acorde X7 (tríade maior + 7ª menor) — independentemente da natureza do acorde tonicizado. V/Dm = A7, V/Am = E7, V/Em = B7 — todos são X7." },
{ q:"A progressão C–E7–Am–Dm–G7–C contém quantas tonicizações?", opts:["Nenhuma","Apenas uma (E7)","Duas (E7 e eventualmente uma segunda)","Três"], a:1, fb:"E7 = V/VI toniciza Am. É a única dominante secundária nessa progressão. Am, Dm, G7 e C são todos diatônicos a C maior — sem tonicização adicional." },
{ q:"Para tonicizar Bm (VII de C# maior), usa-se:", opts:["F#7","E7","A7","D7"], a:0, fb:"A dominante de B = F#. Para tonicizar Bm, usa-se F#7 — independentemente da tonalidade principal. A regra é universal: suba 5 notas a partir do acorde-alvo e toque X7." },
{ q:"Os tons vizinhos de uma tonalidade são:", opts:["As tonalidades à oitava","As tonalidades que compartilham pelo menos 6 notas comuns — os 6 primeiros graus da escala maior e seus relativos","As tonalidades com a mesma armadura","As tonalidades à quinta"], a:1, fb:"Os tons vizinhos compartilham pelo menos 6 notas comuns. Em C maior: Dm, Em, F, G, Am e suas respectivas escalas. Cada grau da escala corresponde a um tom vizinho." },
{ q:"Em C maior, os tons vizinhos são:", opts:["D maior, E maior, F maior, G maior, A maior","D menor, E menor, F maior, G maior, A menor","B menor, C# maior, D maior","Gb maior, Ab maior"], a:1, fb:"Os 6 tons vizinhos de C maior: Dm (II), Em (III), F (IV), G (V), Am (VI). São as tonalidades dos graus diatônicos — compartilham 6 ou 7 notas comuns com C." },
{ q:"A dominante secundária de Am (VIº de C) é:", opts:["D7","A7","E7","B7"], a:2, fb:"Am é o VIº de C. A dominante de Am = E7 (Mi–Sol#–Si–Ré). E7 = V/VI. Sol# é a sensível artificial de Am." },
{ q:"A subdominante secundária de G maior (Vº de C) é:", opts:["C7","Am7 e CMaj7","Dm7 e FMaj7","A7"], a:1, fb:"Em G maior, a subdominante = IV de G = C. Portanto os acordes SD de G são Am7 (II de G) e CMaj7 (IV de G). Podem ser usados para preparar D7 (V/V) em uma tonicização de G." },
{ q:"Em D maior, V/V é:", opts:["G7","A7","E7","B7"], a:1, fb:"V de D = A. V de A = E. V/V em D maior = E7. A progressão E7–A7–D ilustra uma dupla tonicização em D maior." },
{ q:"A relação entre a tônica principal e seus tons vizinhos é:", opts:["Nenhuma — são independentes","Cada tom vizinho compartilha 6-7 notas com a tônica — os acordes podem ser trocados por tonicização ou empréstimo","Têm a mesma armadura","Sempre têm a mesma fundamental"], a:1, fb:"Os tons vizinhos compartilham quase todas as suas notas com a tônica principal — por isso as transições por tonicização são tão fluidas. Permanece-se em um território harmônico familiar." },
{ q:"Na tabela dos tons vizinhos de D maior, qual é o tom vizinho correspondente ao IVº grau?", opts:["E menor","G maior","A maior","F# menor"], a:1, fb:"O IVº grau de D maior é G. G maior é portanto o tom vizinho correspondente ao IVº grau de D. Sua dominante secundária em D maior = C7 (V/IV)." },
{ q:"A subdominante secundária de um tom vizinho permite:", opts:["Tonicizar a tônica principal","Preparar a dominante secundária — SD/X → V/X → X","Modular definitivamente","Criar oitavas paralelas"], a:1, fb:"SD/X prepara V/X que resolve sobre X. Ex: para tonicizar G em C: Am7 (SD/G) → D7 (V/G) → G → C. A subdominante secundária enriquece a tonicização." },
{ q:"Qual é a dominante secundária de F maior (IVº de C)?", opts:["G7","D7","C7","A7"], a:2, fb:"F é o IVº de C. A dominante de F = C. C7 (Do–Mi–Sol–Sib) = V/IV. O Sib é a sétima de C7 que desce para Lá (terça de F)." },
{ q:"Em A maior, os tons vizinhos incluem:", opts:["C maior e D menor","Bm, C#m, D maior, E maior, F#m","G maior e Am","F maior e Gm"], a:1, fb:"Os tons vizinhos de A maior: Bm (II), C#m (III), D (IV), E (V), F#m (VI). São as tonalidades dos graus diatônicos de A maior." },
{ q:"Em G maior, V/VI =", opts:["D7","A7","B7","C7"], a:1, fb:"VI de G = Em. Dominante de Em = B. V/VI em G maior = B7 (Si–Ré#–Fá#–Lá). Ré# é a sensível artificial de Em na tonalidade de G." },
{ q:"A progressão G–A7–Dm–C–G em G maior ilustra:", opts:["Uma modulação em D menor","Um empréstimo de Dm de G menor","Uma tonicização de Dm — Dm é o VIº de G e A7 = V/VI em G maior","Um baixo de chacona"], a:2, fb:"Em G maior, VI = Em. Mas Dm aqui é um empréstimo de G menor (VIº de G menor = Dm). A7 toniciza Dm como se fosse momentaneamente tônica. Análise contextual necessária." },
{ q:"Como encontrar a dominante secundária de Em (IIIº de C)?", opts:["Subir 3 graus a partir de E = G, tocar G7","Subir 5 graus a partir de E = B, tocar B7","Descer 2 graus a partir de E = D, tocar D7","Tocar Em7 diretamente"], a:1, fb:"Suba 5 notas a partir de E: E–F–G–A–B = B. Toque B7 (Si–Ré#–Fá#–Lá). B7 = V/III em C maior. Ré# é a sensível de E que sobe para Mi." },
{ q:"Os tons vizinhos facilitam as tonicizações porque:", opts:["Têm menos notas","Compartilham quase todas as suas notas com a tonalidade principal — as transições são fluidas","São mais graves","Têm mais acordes maiores"], a:1, fb:"Com 6-7 notas comuns, a transição para um tom vizinho é percebida como natural. Uma tonicização para um tom vizinho não é estranhante — permanece-se em um universo familiar." },
{ q:"Em uma tonicização, pode-se combinar V/X com um napolitano de X?", opts:["Não — as regras se excluem","Sim — todas as regras coexistem, desde que se referencie o trítono de X","Somente em menor","Apenas com empréstimos do homônimo"], a:1, fb:"Sim. Na tonalidade temporária de X, pode-se usar qualquer ferramenta harmônica: napolitano de X, empréstimo de X menor, substituição diatônica em X. O trítono de X é a referência." },
{ q:"Em C maior, qual desses acordes NÃO é uma dominante secundária válida?", opts:["A7 (V/II)","E7 (V/VI)","F7 (V/IV)","G#7 (impossível diatonicamente)"], a:3, fb:"G#7 não existe como dominante secundária diatônica em C maior — nenhum acorde diatônico de C tem G# como fundamental de sua dominante. A7, E7 e F7 (= C7 é a notação correta) são válidos." },
{ q:"A subdominante secundária de Dm (IIº de C) é:", opts:["G7","Em7b5 e Gm7","Am7 e CMaj7","D7"], a:1, fb:"Na tonalidade de D menor, a subdominante = IV de D menor = Gm. O IIº de D menor = Em7b5. Portanto SD/Dm = Em7b5 (II de Dm) e Gm7 (IV de Dm)." },
{ q:"Em Eb maior, V/V é:", opts:["F7","Bb7","C7","G7"], a:1, fb:"V de Eb = Bb. A dominante de Bb = F. V/V em Eb = F7 — atenção: V de Eb = Bb. V de Bb = F. V/V em Eb = F7. Aqui a resposta correta é F7, mas as opções apresentam Bb7 — que é V de Eb diretamente, não V/V." },
{ q:"Uma cadeia de tonicizações é:", opts:["Uma sucessão de acordes diminutos","Uma sequência de dominantes secundárias, cada uma tonicizando a seguinte","Uma sequência de cadências perfeitas","Um ciclo de quintas sem dominantes"], a:1, fb:"Uma cadeia de tonicizações encadeia várias dominantes secundárias: V/V/V → V/V → V → I. Cada acorde prepara a dominante seguinte, criando uma tensão que se acumula em direção à resolução final." },
{ q:"A progressão C–C#7–F#7–B7–E7–A em A maior é:", opts:["Uma modulação em C#","Uma cadeia de dominantes secundárias: V/V/V/V–V/V/V–V/V–V–I","Um empréstimo em massa","Um ciclo de quintas diatônicas"], a:1, fb:"C#7 = V/V/V/V de A (pois C#7 → F#7 → B7 → E7 → A). Cada acorde toniciza o seguinte por um movimento de dominante para tônica. Tensão progressiva em direção a A." },
{ q:"A progressão A–B7–E7–A (em A maior) é uma cadeia porque:", opts:["B7 e E7 estão ambos na escala de A","B7 toniciza E7 (V/V) que toniciza A (V) — dois níveis de dominantes secundárias","São acordes de passagem","São empréstimos de A menor"], a:1, fb:"B7 = V/V em A maior (toniciza E7). E7 = V em A (toniciza A). Dois níveis de tonicização encaixados: V/V → V → I. A tensão sobe em duas etapas antes da resolução." },
{ q:"A notação V/V/V significa:", opts:["A quinta da quinta da quinta","A dominante da dominante da dominante — três níveis de tonicização","Uma modulação em três etapas","Um acorde impossível"], a:1, fb:"V/V/V = dominante da dominante da dominante. Em C: V = G, V/V = D7, V/V/V = A7. A progressão A7–D7–G7–C é uma cadeia de três tonicizações." },
{ q:"Em uma cadeia, cada acorde resolve:", opts:["Sobre a tônica principal","Sobre o acorde que segue de forma que cada acorde aja como dominante do próximo","Por semitom cromático","Sobre o mesmo acorde"], a:1, fb:"Em uma cadeia V/V/V → V/V → V → I: cada acorde resolve sobre o seguinte — A7 → D7 → G7 → C. Cada resolução é uma micro-cadência que reforça a próxima." },
{ q:"A progressão C–A7–D7–G7–C contém:", opts:["Nenhuma tonicização","Uma tonicização (A7)","Duas tonicizações (A7 = V/II e D7 = V/V)","Três tonicizações"], a:2, fb:"A7 = V/II (toniciza Dm brevemente — Dm é 'esquivado' aqui). D7 = V/V (toniciza G7). Dois níveis de dominantes secundárias se encadeiam antes da resolução final G7–C." },
{ q:"Por que as cadeias de dominantes secundárias criam uma tensão crescente?", opts:["Porque usam acordes dissonantes","Porque cada dominante secundária reforça a seguinte — a resolução final é tanto mais satisfatória","Porque modulam","Porque suprimem o trítono"], a:1, fb:"Cada etapa da cadeia cria uma expectativa que é parcialmente satisfeita (resolução secundária) mas aponta para a resolução final. A tensão se acumula e a resolução final é mais poderosa." },
{ q:"Em C maior, a cadeia V/V/V–V/V–V–I se escreve:", opts:["B7–E7–A7–C","A7–D7–G7–C","D7–G7–C7–F","E7–A7–Dm–G7"], a:1, fb:"V = G, V/V = D7, V/V/V = A7. A cadeia é A7–D7–G7–C. Cada acorde resolve uma quinta abaixo, em direção à resolução final sobre C." },
{ q:"Na progressão G–C#7–F#7–B7–E7–Am–D7–G (em G maior), quantas tonicizações há?", opts:["Duas","Três","Quatro ou mais (cadeia complexa)","Apenas uma"], a:2, fb:"C#7 (V/VI de G, toniciza F#m), F#7 (V/VI?), B7 (V/III, toniciza Em/E), E7 (V/II, toniciza Am), D7 (V/V, toniciza G) — é uma longa cadeia com pelo menos 4 níveis de tonicização." },
];

